import { GoogleGenAI } from "@google/genai";
import { ExerciseType, Level } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateStreamingExercise = async (
  type: ExerciseType,
  level: Level,
  topic: string,
  onChunk: (chunk: string) => void
) => {
  const prompt = `Actúa como un experto terapeuta del lenguaje infantil. 
  Genera un ejercicio de tipo "${type}" para un niño de nivel "${level}" sobre el tema "${topic}".

  El formato debe ser JSON con los campos:
  - content: El texto del ejercicio (lo que el niño ve).
  - target: La palabra o frase objetivo (para articulación).
  - options: (Opcional, para comprensión) Lista de 3 opciones.
  - hint: Una pista amable.

  Reglas:
  1. Vocabulario simple y positivo.
  2. Sin diagnósticos.
  3. Divertido y corto.
  4. Solo devuelve el JSON puro.`;

  try {
    const responseStream = await ai.models.generateContentStream({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      const text = chunk.text;
      if (text) {
        fullText += text;
        onChunk(fullText);
      }
    }
    return fullText;
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Simulation fallback if no key
    const mock = `{"content": "Mira el gato y dime su sonido", "target": "miau", "options": ["guau", "miau", "pío"], "hint": "Hace miau miau"}`;
    for (let i = 0; i <= mock.length; i++) {
      await new Promise(r => setTimeout(r, 20));
      onChunk(mock.substring(0, i));
    }
    return mock;
  }
};

export const speak = (text: string) => {
  if (!('speechSynthesis' in window)) return;
  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'es-ES';
  utterance.rate = 0.9;
  window.speechSynthesis.speak(utterance);
};

export const startRecognition = (onResult: (result: string) => void, onError: (err: any) => void) => {
  const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
  if (!SpeechRecognition) {
    onError("Browser doesn't support Speech Recognition");
    return null;
  }

  const recognition = new SpeechRecognition();
  recognition.lang = 'es-ES';
  recognition.interimResults = false;
  recognition.maxAlternatives = 1;

  recognition.onresult = (event: any) => {
    const result = event.results[0][0].transcript;
    onResult(result);
  };

  recognition.onerror = (event: any) => {
    onError(event.error);
  };

  recognition.start();
  return recognition;
};

export const compareText = (input: string, target: string): number => {
  const normalize = (str: string) => str.toLowerCase().trim().replace(/[.,/#!$%^&*;:{}=\-_`~()]/g, "");
  const s1 = normalize(input);
  const s2 = normalize(target);

  if (s1 === s2) return 1;

  // Simple similarity check (inclusion or partial)
  if (s1.includes(s2) || s2.includes(s1)) return 0.8;

  return 0.2;
};

import React, { useEffect, useRef } from 'react';

interface LottiePlayerProps {
  url: string;
  loop?: boolean;
  autoplay?: boolean;
  className?: string;
  animationData?: any;
}

const LottiePlayer: React.FC<LottiePlayerProps> = ({ url, loop = true, autoplay = true, className, animationData }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Dynamically load lottie-web if not already present
    const loadLottie = async () => {
      const lottie = (await import('lottie-web')).default;
      if (containerRef.current) {
        const anim = lottie.loadAnimation({
          container: containerRef.current,
          renderer: 'svg',
          loop,
          autoplay,
          path: animationData ? undefined : url,
          animationData: animationData,
        });
        return () => anim.destroy();
      }
    };
    loadLottie();
  }, [url, animationData, loop, autoplay]);

  return <div ref={containerRef} className={className} />;
};

export default LottiePlayer;

