import React, { useState } from 'react';
import Layout from '../components/Layout';
import { generateStreamingExercise } from '../services/geminiService';
import { ExerciseType, Level } from '../types';
import { motion } from 'framer-motion';

const AIGenerator: React.FC = () => {
  const [type, setType] = useState<ExerciseType>(ExerciseType.ARTICULATION);
  const [level, setLevel] = useState<Level>(Level.BASIC);
  const [topic, setTopic] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [streamedContent, setStreamedContent] = useState('');
  const [generatedExercise, setGeneratedExercise] = useState<any>(null);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setStreamedContent('');
    setGeneratedExercise(null);

    const result = await generateStreamingExercise(type, level, topic, (chunk) => {
      setStreamedContent(chunk);
    });

    try {
      // Clean up markdown if AI returned it
      const jsonStr = result.replace(/```json/g, '').replace(/```/g, '').trim();
      setGeneratedExercise(JSON.parse(jsonStr));
    } catch (e) {
      console.error("Failed to parse JSON", e);
    }
    setIsGenerating(false);
  };

  return (
    <Layout>
      <div className="max-w-4xl mx-auto">
        <h2 className="text-3xl font-bold mb-2">Generador de IA Mágica</h2>
        <p className="text-gray-600 mb-8">Crea ejercicios personalizados para tus pacientes en segundos.</p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="bg-white p-6 border rounded-2xl shadow-sm">
            <h3 className="font-bold mb-4 text-gray-700">Configuración</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Módulo</label>
                <select 
                  className="w-full border rounded-lg p-2 bg-white"
                  value={type}
                  onChange={(e) => setType(e.target.value as ExerciseType)}
                >
                  {Object.values(ExerciseType).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nivel</label>
                <div className="flex gap-2">
                  {Object.values(Level).map(l => (
                    <button
                      key={l}
                      onClick={() => setLevel(l)}
                      className={`flex-1 py-2 text-sm rounded-lg border font-bold ${level === l ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-600'}`}
                    >
                      {l}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Tema / Objetivo (Ej: Piratas, Fonema R)</label>
                <input 
                  type="text" 
                  className="w-full border rounded-lg p-2"
                  placeholder="Dinos qué necesita el niño..."
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                />
              </div>

              <button
                onClick={handleGenerate}
                disabled={isGenerating || !topic}
                className={`w-full py-4 rounded-xl font-bold shadow-lg transition-all ${isGenerating ? 'bg-gray-400 cursor-not-allowed' : 'bg-gradient-to-r from-purple-500 to-indigo-600 text-white hover:scale-105'}`}
              >
                {isGenerating ? 'Generando Magia...' : '✨ Generar Ejercicio'}
              </button>
            </div>
          </div>

          <div className="bg-white p-6 border rounded-2xl shadow-sm min-h-[400px] flex flex-col">
            <h3 className="font-bold mb-4 text-gray-700">Vista Previa</h3>

            <div className="flex-1 bg-gray-50 rounded-xl p-4 font-mono text-sm overflow-auto mb-4 relative">
              {isGenerating && (
                <div className="absolute top-2 right-2 animate-pulse text-purple-500 font-bold">AI STREAMING</div>
              )}
              {streamedContent || 'Esperando instrucciones...'}
            </div>

            {generatedExercise && (
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="border-t pt-4">
                <div className="bg-blue-50 p-4 rounded-lg mb-4">
                  <p className="text-sm font-bold text-blue-800">Resultado Interpretado:</p>
                  <p className="text-gray-700 mt-1">{generatedExercise.content}</p>
                  {generatedExercise.target && <p className="text-xs text-blue-600 mt-1">Objetivo: {generatedExercise.target}</p>}
                </div>
                <div className="flex gap-2">
                   <button className="flex-1 bg-green-500 text-white font-bold py-2 rounded-lg text-sm">Aprobar y Guardar</button>
                   <button onClick={() => setGeneratedExercise(null)} className="flex-1 bg-gray-200 text-gray-600 font-bold py-2 rounded-lg text-sm">Descartar</button>
                </div>
              </motion.div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default AIGenerator;

import React, { useState, useEffect } from 'react';
import Layout from '../components/Layout';
import { motion, AnimatePresence } from 'framer-motion';
import LottiePlayer from '../components/LottiePlayer';
import { LOTTIE_URLS } from '../constants';
import { speak, startRecognition, compareText } from '../services/speechService';
import { ExerciseType, Level } from '../types';

const ChildPlay: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<'welcome' | 'playing' | 'reward'>('welcome');
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [exerciseIndex, setExerciseIndex] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [feedback, setFeedback] = useState('');
  const [score, setScore] = useState(0);

  const exercises = [
    { type: ExerciseType.ARTICULATION, content: 'Di: "Rosa"', target: 'rosa', hint: 'Pon la lengua arriba' },
    { type: ExerciseType.VOCABULARY, content: '¿Qué animal es este?', target: 'elefante', hint: 'Tiene una trompa larga', imageUrl: 'https://picsum.photos/400/300?random=1' },
    { type: ExerciseType.COMPREHENSION, content: '¿Cuál es el color del cielo?', target: 'azul', options: ['azul', 'rojo', 'verde'] }
  ];

  const currentExercise = exercises[exerciseIndex];

  const handleStart = () => {
    setCurrentStep('playing');
    setMascotState(LOTTIE_URLS.mascot_idle);
    speak("¡Hola! Vamos a jugar juntos. Escucha con atención.");
  };

  const handleListen = () => {
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('Te escucho...');

    const recognition = startRecognition(
      (result) => {
        setIsListening(false);
        const similarity = compareText(result, currentExercise.target);
        if (similarity > 0.7) {
          handleSuccess();
        } else {
          handleRepeat();
        }
      },
      (err) => {
        setIsListening(false);
        setFeedback('No te oí bien, ¿repitimos?');
        setMascotState(LOTTIE_URLS.mascot_idle);
      }
    );
  };

  const handleSuccess = () => {
    setMascotState(LOTTIE_URLS.mascot_celebrate);
    setFeedback('¡SÚPER BIEN!');
    setScore(s => s + 10);
    speak("¡Súper! Lo hiciste genial.");
    setTimeout(() => {
      if (exerciseIndex < exercises.length - 1) {
        setExerciseIndex(idx => idx + 1);
        setMascotState(LOTTIE_URLS.mascot_idle);
        setFeedback('');
      } else {
        setCurrentStep('reward');
      }
    }, 2000);
  };

  const handleRepeat = () => {
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('Casi... ¡intenta otra vez!');
    speak("Casi casi, inténtalo una vez más, tú puedes.");
  };

  return (
    <Layout role="child">
      <div className="relative h-[80vh] flex flex-col items-center justify-center">

        {/* Progress Bar */}
        <div className="absolute top-0 w-full max-w-2xl px-4">
           <div className="h-4 bg-white/50 rounded-full overflow-hidden border border-white/20">
              <motion.div 
                className="h-full bg-gradient-to-r from-green-400 to-blue-500"
                initial={{ width: 0 }}
                animate={{ width: `${(exerciseIndex / exercises.length) * 100}%` }}
              />
           </div>
        </div>

        <AnimatePresence mode="wait">
          {currentStep === 'welcome' && (
            <motion.div 
              key="welcome"
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 1.2, opacity: 0 }}
              className="text-center"
            >
              <div className="w-64 h-64 mx-auto mb-8">
                <LottiePlayer url={LOTTIE_URLS.mascot_happy} />
              </div>
              <h2 className="text-4xl font-black text-blue-900 mb-8">¡HOLA, AMIGUITO!</h2>
              <button 
                onClick={handleStart}
                className="bg-yellow-400 hover:bg-yellow-500 text-blue-900 text-2xl font-black px-12 py-6 rounded-full shadow-2xl transform active:scale-90 transition-all border-b-8 border-yellow-600"
              >
                EMPEZAR
              </button>
            </motion.div>
          )}

          {currentStep === 'playing' && (
            <motion.div 
              key="playing"
              initial={{ x: 300, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              exit={{ x: -300, opacity: 0 }}
              className="w-full max-w-3xl flex flex-col items-center"
