              <h2 className="text-4xl font-black text-blue-900 mb-8 drop-shadow-sm">¡HOLA, AMIGUITO!</h2>

              <button 
                onClick={handleStart}
                className="bg-yellow-400 hover:bg-yellow-500 text-blue-900 text-2xl font-black px-12 py-6 rounded-full shadow-2xl transform active:scale-90 transition-all border-b-8 border-yellow-600 relative z-20"
              >
                EMPEZAR
              </button>
            </motion.div>
          )}

          {currentStep === 'playing' && (
            <motion.div 
              key="playing"
              initial={{ x: 300, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              exit={{ x: -300, opacity: 0 }}
              className="w-full max-w-3xl flex flex-col items-center z-10"
            >
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-center w-full">
                <div className="relative group">
                  <div className="bg-white rounded-3xl p-8 shadow-xl text-center min-h-[300px] flex flex-col justify-center border-4 border-blue-200">
