                    <h3 className="text-3xl font-bold text-gray-800 mb-4">{currentExercise.content}</h3>
                    {currentExercise.options && (
                      <div className="flex flex-wrap gap-2 justify-center">
                        {currentExercise.options.map(opt => (
                          <button key={opt} onClick={() => opt === currentExercise.target ? handleSuccess() : handleRepeat()} className="bg-blue-100 px-4 py-2 rounded-xl font-bold text-blue-700 hover:bg-blue-200">{opt}</button>
                        ))}
                      </div>
                    )}
                  </div>

                  {feedback && (
