import React, { useEffect, useRef, useState } from 'react';

interface LottiePlayerProps {
  url: string;
  loop?: boolean;
  autoplay?: boolean;
  className?: string;
  animationData?: any;
}

const LottiePlayer: React.FC<LottiePlayerProps> = ({ url, loop = true, autoplay = true, className, animationData }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    let anim: any;

    const loadLottie = async () => {
      try {
        const lottie = (await import('lottie-web')).default;
        if (containerRef.current) {
          anim = lottie.loadAnimation({
            container: containerRef.current,
            renderer: 'svg',
            loop,
            autoplay,
            path: animationData ? undefined : url,
            animationData: animationData,
          });

          anim.addEventListener('DOMLoaded', () => setHasError(false));
          anim.addEventListener('data_failed', () => setHasError(true));
        }
      } catch (error) {
        console.error("Error loading Lottie:", error);
        setHasError(true);
      }
    };

    loadLottie();

    return () => {
      if (anim) anim.destroy();
    };
  }, [url, animationData, loop, autoplay]);

  if (hasError) {
    // Si falla, retornamos un div vacío o un fallback sutil para no romper la UI
    return <div className={`${className} bg-transparent flex items-center justify-center text-4xl`}>✨</div>;
  }

  return <div ref={containerRef} className={className} />;
};

export default LottiePlayer;

