import React, { useEffect, useRef, useState, memo } from 'react';

interface LottiePlayerProps {
  url: string;
  loop?: boolean;
  autoplay?: boolean;
  className?: string;
  animationData?: any;
}

const LottiePlayer: React.FC<LottiePlayerProps> = ({ url, loop = true, autoplay = true, className, animationData }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [hasError, setHasError] = useState(false);
  const animRef = useRef<any>(null);

  useEffect(() => {
    let isMounted = true;

    const loadLottie = async () => {
      try {
        const lottie = (await import('lottie-web')).default;
        if (containerRef.current && isMounted) {
          // Destruir animación previa si existe
          if (animRef.current) animRef.current.destroy();

          animRef.current = lottie.loadAnimation({
            container: containerRef.current,
            renderer: 'svg',
            loop,
            autoplay,
            path: animationData ? undefined : url,
            animationData: animationData,
          });

          animRef.current.addEventListener('DOMLoaded', () => {
            if (isMounted) setHasError(false);
          });

          animRef.current.addEventListener('data_failed', () => {
            if (isMounted) setHasError(true);
          });
        }
      } catch (error) {
        console.warn("Lottie loading failed, using fallback:", error);
        if (isMounted) setHasError(true);
      }
    };

    loadLottie();

    return () => {
      isMounted = false;
      if (animRef.current) animRef.current.destroy();
    };
  }, [url, animationData, loop, autoplay]);

  if (hasError) {
    return (
      <div className={`${className} bg-blue-50/50 rounded-full flex items-center justify-center text-4xl animate-pulse`}>
        ✨
      </div>
    );
  }

  return <div ref={containerRef} className={`${className} outline-none`} />;
};

// Usamos memo para evitar re-renderizados innecesarios si las props no cambian
export default memo(LottiePlayer);

