import React, { useEffect, useRef, useState, memo } from 'react';

interface LottiePlayerProps {
  url: string;
  loop?: boolean;
  autoplay?: boolean;
  className?: string;
  animationData?: any;
  isSticker?: boolean; // Nueva prop para activar efecto de pegatina
}

const LottiePlayer: React.FC<LottiePlayerProps> = ({ 
  url, 
  loop = true, 
  autoplay = true, 
  className, 
  animationData,
  isSticker = true 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [hasError, setHasError] = useState(false);
  const animRef = useRef<any>(null);

  useEffect(() => {
    let isMounted = true;

    const loadLottie = async () => {
      try {
        const lottie = (await import('lottie-web')).default;
        if (containerRef.current && isMounted) {
          // Destruir animación previa si existe
          if (animRef.current) animRef.current.destroy();

          animRef.current = lottie.loadAnimation({
            container: containerRef.current,
            renderer: 'svg',
            loop,
            autoplay,
            path: animationData ? undefined : url,
            animationData: animationData,
            rendererSettings: {
              preserveAspectRatio: 'xMidYMid slice',
              // Aseguramos que el SVG sea accesible para filtros CSS
              className: 'lottie-svg-element'
            }
          });

          animRef.current.addEventListener('DOMLoaded', () => {
            if (isMounted) setHasError(false);
          });

          animRef.current.addEventListener('data_failed', () => {
            if (isMounted) setHasError(true);
          });
        }
      } catch (error) {
        console.warn("Lottie loading failed, using fallback:", error);
        if (isMounted) setHasError(true);
      }
    };

    loadLottie();

    return () => {
      isMounted = false;
      if (animRef.current) animRef.current.destroy();
    };
  }, [url, animationData, loop, autoplay]);

  if (hasError) {
    return (
      <div className={`${className} bg-blue-50/50 rounded-full flex items-center justify-center text-4xl animate-pulse`}>
        ✨
      </div>
    );
  }

  // Combinamos las clases de estilo 2D y sticker
  const drawingClasses = `lottie-2d-drawing ${isSticker ? 'lottie-sticker' : ''}`;

  return (
    <div 
      ref={containerRef} 
      className={`${className} ${drawingClasses} outline-none transition-transform duration-300`} 
    />
  );
};

export default memo(LottiePlayer);

import { GoogleGenAI } from "@google/genai";
import { ExerciseType, Level } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateStreamingExercise = async (
  type: ExerciseType,
  level: Level,
  topic: string,
  onChunk: (chunk: string) => void
) => {
  const prompt = `Actúa como un experto terapeuta del lenguaje infantil. 
  Genera un ejercicio de tipo "${type}" para un niño de nivel "${level}" sobre el tema "${topic}".

  El formato debe ser JSON con los campos:
  - content: El texto del ejercicio (lo que el niño ve).
  - target: La palabra o frase objetivo (ej: "perro").
  - options: (Opcional, para comprensión) Lista de 3 opciones cortas.
  - hint: Una pista amable y corta.
  - image_keyword: Una sola palabra en inglés que describa el objeto principal para buscar una imagen (ej: "dog", "apple", "rocket").

  Reglas:
  1. Vocabulario simple y positivo.
  2. Sin diagnósticos.
  3. Divertido y corto.
  4. Solo devuelve el JSON puro, sin bloques de código markdown.`;

  try {
    const responseStream = await ai.models.generateContentStream({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      const text = chunk.text;
      if (text) {
        fullText += text;
        onChunk(fullText);
      }
    }
    return fullText;
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Simulation fallback with more context
    const mock = `{"content": "¿Cómo hace este animalito?", "target": "miau", "options": ["guau", "miau", "pío"], "hint": "Es un gatito", "image_keyword": "cat"}`;
    for (let i = 0; i <= mock.length; i++) {
      await new Promise(r => setTimeout(r, 15));
      onChunk(mock.substring(0, i));
    }
    return mock;
  }
};

import React, { useState, useEffect } from 'react';
import Layout from '../components/Layout';
import { motion, AnimatePresence } from 'framer-motion';
import LottiePlayer from '../components/LottiePlayer';
import { LOTTIE_URLS } from '../constants';
import { speak, startRecognition, compareText } from '../services/speechService';
import { ExerciseType, Level } from '../types';

const ChildPlay: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<'welcome' | 'playing' | 'reward'>('welcome');
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [exerciseIndex, setExerciseIndex] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [feedback, setFeedback] = useState('');
  const [score, setScore] = useState(0);

  // Ejercicios iniciales con imágenes precisas
  const exercises = [
    { 
      type: ExerciseType.ARTICULATION, 
      content: 'Mira la flor y di: "Rosa"', 
      target: 'rosa', 
      hint: 'Pon la lengua arriba',
      imageUrl: 'https://images.unsplash.com/photo-1559563458-527698bf5295?w=400&h=300&fit=crop' 
    },
    { 
      type: ExerciseType.VOCABULARY, 
      content: '¿Qué animal tiene esta trompa?', 
      target: 'elefante', 
      hint: 'Es muy grande y gris', 
      imageUrl: 'https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=400&h=300&fit=crop' 
    },
    { 
      type: ExerciseType.COMPREHENSION, 
      content: '¿Cuál de estos es el color del cielo?', 
      target: 'azul', 
      options: ['azul', 'rojo', 'verde'],
      imageUrl: 'https://images.unsplash.com/photo-1501630834273-4b5604d2ee31?w=400&h=300&fit=crop'
    }
  ];

  const currentExercise = exercises[exerciseIndex];

  const handleStart = () => {
    setCurrentStep('playing');
    setMascotState(LOTTIE_URLS.mascot_idle);
    speak("¡Hola! Vamos a jugar juntos. ¿Estás listo?");
  };

  const handleListen = () => {
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('Te escucho...');

    const recognition = startRecognition(
      (result) => {
        setIsListening(false);
        const similarity = compareText(result, currentExercise.target);
        if (similarity > 0.6) handleSuccess();
        else handleRepeat();
      },
      (err) => {
        console.error(err);
        setIsListening(false);
        setFeedback('No te oí bien...');
        setMascotState(LOTTIE_URLS.mascot_idle);
      }
    );
  };

  const handleSuccess = () => {
