import React, { useState } from 'react';
import Layout from '../components/Layout';
import { generateStreamingExercise } from '../services/geminiService';
import { ExerciseType, Level } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const AIGenerator: React.FC = () => {
  const [type, setType] = useState<ExerciseType>(ExerciseType.ARTICULATION);
  const [level, setLevel] = useState<Level>(Level.BASIC);
  const [topic, setTopic] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [streamedContent, setStreamedContent] = useState('');
  const [generatedExercise, setGeneratedExercise] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setError(null);
    setStreamedContent('');
    setGeneratedExercise(null);

    try {
      const result = await generateStreamingExercise(type, level, topic, (chunk) => {
        setStreamedContent(chunk);
      });

      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (!jsonMatch) throw new Error("Formato inválido.");

      const parsed = JSON.parse(jsonMatch[0].trim());
      if (!parsed.content) throw new Error("Incompleto.");

      // Si tiene keyword, generamos un URL de imagen de stock confiable
      if (parsed.image_keyword) {
        parsed.imageUrl = `https://loremflickr.com/400/300/${parsed.image_keyword}`;
      }

      setGeneratedExercise(parsed);
    } catch (e) {
      console.error(e);
      setError("¡Ups! La varita mágica falló. Intenta con otro tema.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <Layout>
      <div className="max-w-5xl mx-auto px-4">
        <header className="mb-10 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
