          <button 
            onClick={() => window.location.hash = '#/dashboard'}
            className="bg-white border-4 border-gray-100 px-6 py-3 rounded-2xl font-black text-gray-500 hover:text-blue-500 transition-all"
          >
            ⬅️ Volver
          </button>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          {/* Configuración */}
          <div className="bg-white p-8 rounded-[3rem] shadow-xl border-4 border-gray-50">
            <h3 className="text-2xl font-black mb-8 text-gray-800">1. Personaliza</h3>
            <div className="space-y-8">
              <div>
                <label className="block text-xs font-black text-gray-400 mb-3 uppercase tracking-widest">Tipo de actividad</label>
                <select 
                  className="w-full border-4 border-gray-50 rounded-3xl p-5 bg-gray-50/50 focus:border-purple-300 focus:outline-none font-bold text-gray-700"
                  value={type}
                  onChange={(e) => setType(e.target.value as ExerciseType)}
                >
                  {Object.values(ExerciseType).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>

              <div>
                <label className="block text-xs font-black text-gray-400 mb-3 uppercase tracking-widest">Dificultad</label>
                <div className="flex gap-3">
                  {Object.values(Level).map(l => (
                    <button
                      key={l}
                      onClick={() => setLevel(l)}
                      className={`flex-1 py-4 rounded-2xl border-4 font-black transition-all ${level === l ? 'bg-purple-600 text-white border-purple-600 shadow-lg scale-105' : 'bg-gray-50 text-gray-400 border-transparent hover:border-purple-200'}`}
                    >
                      {l}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-black text-gray-400 mb-3 uppercase tracking-widest">Tema Principal</label>
                <input 
                  type="text" 
                  className="w-full border-4 border-gray-50 rounded-3xl p-5 bg-gray-50/50 focus:border-purple-300 focus:outline-none font-bold"
                  placeholder="Ej: El espacio, gatitos, comida..."
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                />
              </div>

              <motion.button
                whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
                onClick={handleGenerate}
                disabled={isGenerating || !topic}
                className={`w-full py-6 rounded-3xl font-black shadow-2xl transition-all flex items-center justify-center gap-4 ${isGenerating || !topic ? 'bg-gray-200 text-gray-400' : 'bg-gradient-to-r from-purple-500 to-indigo-600 text-white'}`}
              >
                {isGenerating ? "CREANDO MAGIA..." : "✨ GENERAR JUEGO"}
              </motion.button>
            </div>
          </div>

          {/* Vista Previa */}
          <div className="flex flex-col gap-6">
            <div className="bg-white p-8 rounded-[3rem] shadow-xl border-4 border-gray-50 flex-grow min-h-[500px]">
              <h3 className="text-2xl font-black mb-8 text-gray-800">2. Previsualiza</h3>

              <AnimatePresence>
                {error && <p className="text-red-500 font-bold mb-4">⚠️ {error}</p>}
              </AnimatePresence>

              <div className="bg-gray-900 rounded-3xl p-6 font-mono text-[10px] text-green-400 overflow-auto max-h-[150px] mb-8 border-4 border-gray-800">
                {streamedContent || "// Esperando..."}
              </div>

              {generatedExercise && (
                <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="p-6 bg-blue-50/50 rounded-[2rem] border-4 border-blue-100">
