              {!isGenerating && !generatedExercise && (
                <div className="flex flex-col items-center justify-center h-[300px] text-gray-300 opacity-50">
                  <span className="text-8xl mb-4">🎨</span>
                  <p className="font-black">¡Aquí aparecerá tu creación!</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
};

