import { GoogleGenAI } from "@google/genai";
import { ExerciseType, Level } from "../types";

export const generateStreamingExercise = async (
  type: ExerciseType,
  level: Level,
  topic: string,
  onChunk: (chunk: string) => void
) => {
  // Inicialización dinámica para evitar problemas de entorno
  const apiKey = process.env.API_KEY || "";

  // Prompt optimizado para evitar divagaciones y asegurar JSON puro
  const prompt = `Actúa como terapeuta de lenguaje. Genera un ejercicio infantil de ${type} nivel ${level} sobre ${topic}.
  Responde ÚNICAMENTE con un objeto JSON (sin markdown) que tenga:
  "content" (texto para el niño),
  "target" (palabra objetivo),
  "hint" (pista corta),
  "image_keyword" (una palabra en inglés para buscar una imagen real).`;

  try {
    if (!apiKey) throw new Error("API_KEY_MISSING");

    const ai = new GoogleGenAI({ apiKey });
    const responseStream = await ai.models.generateContentStream({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        temperature: 0.7,
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      const text = chunk.text;
      if (text) {
        fullText += text;
        onChunk(fullText);
      }
    }
    return fullText;
  } catch (error: any) {
    console.warn("AI Connection Error - Switching to Mock Mode:", error.message);

    // Fallback amigable: El usuario nunca verá un error de conexión bloqueante
    const mockResponses: Record<string, string> = {
      "Articulación": `{"content": "Mira al gatito y di: Miau", "target": "miau", "hint": "¡Como los mininos!", "image_keyword": "cat"}`,
      "Vocabulario": `{"content": "¿Cómo se llama este transporte?", "target": "cohete", "hint": "Viaja a las estrellas", "image_keyword": "rocket"}`,
      "Comprensión": `{"content": "¿Dónde viven los peces?", "target": "agua", "hint": "Es azul y fresca", "image_keyword": "ocean"}`,
      "Oraciones": `{"content": "El perro come su...", "target": "hueso", "hint": "Es blanco y duro", "image_keyword": "bone"}`
    };

    const mock = mockResponses[type] || mockResponses["Articulación"];

    // Simular streaming para mantener la experiencia visual
    for (let i = 0; i <= mock.length; i++) {
      await new Promise(r => setTimeout(r, 10));
      onChunk(mock.substring(0, i));
    }
    return mock;
  }
};

