import React, { useEffect, useRef, useState, memo } from 'react';

interface LottiePlayerProps {
  url: string;
  loop?: boolean;
  autoplay?: boolean;
  className?: string;
  animationData?: any;
  isSticker?: boolean; 
}

const LottiePlayer: React.FC<LottiePlayerProps> = ({ 
  url, 
  loop = true, 
  autoplay = true, 
  className = "", 
  animationData,
  isSticker = true 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [hasError, setHasError] = useState(false);
  const animRef = useRef<any>(null);

  useEffect(() => {
    let isMounted = true;

    const loadLottie = async () => {
      try {
        setHasError(false); // Reset error state on URL change
        const lottie = (await import('lottie-web')).default;

        if (containerRef.current && isMounted) {
          if (animRef.current) animRef.current.destroy();

          animRef.current = lottie.loadAnimation({
            container: containerRef.current,
            renderer: 'svg',
            loop,
            autoplay,
            path: animationData ? undefined : url,
            animationData: animationData,
            rendererSettings: {
              preserveAspectRatio: 'xMidYMid slice',
              className: 'lottie-svg-element'
            }
          });

          animRef.current.addEventListener('DOMLoaded', () => {
            if (isMounted) setHasError(false);
          });

          animRef.current.addEventListener('data_failed', () => {
            console.error("Lottie data failed to load for:", url);
            if (isMounted) setHasError(true);
          });

          animRef.current.addEventListener('error', (e: any) => {
            console.error("Lottie encountered an error:", e);
            if (isMounted) setHasError(true);
          });
        }
      } catch (error) {
        console.warn("Lottie critical failure, using fallback UI:", error);
        if (isMounted) setHasError(true);
      }
    };

    loadLottie();

    return () => {
      isMounted = false;
      if (animRef.current) animRef.current.destroy();
    };
  }, [url, animationData, loop, autoplay]);

  if (hasError) {
    // Fallback UI: Un círculo brillante con un emoji de estrellas animado
    return (
      <div 
        className={`${className} bg-gradient-to-br from-blue-100 to-white rounded-full flex items-center justify-center text-5xl shadow-inner border-4 border-white transition-all duration-500 ${isSticker ? 'lottie-sticker' : ''}`}
        style={{ minWidth: '120px', minHeight: '120px' }}
      >
        <div className="animate-bounce">
          <span className="drop-shadow-lg" role="img" aria-label="magic-fallback">✨</span>
        </div>
      </div>
    );
  }

  const drawingClasses = `lottie-2d-drawing ${isSticker ? 'lottie-sticker' : ''}`;

  return (
    <div 
      ref={containerRef} 
      className={`${className} ${drawingClasses} outline-none transition-transform duration-300 flex items-center justify-center`} 
    />
  );
};

export default memo(LottiePlayer);

