import React, { useState, useEffect } from 'react';
import Layout from '../components/Layout';
import { motion, AnimatePresence } from 'framer-motion';
import LottiePlayer from '../components/LottiePlayer';
import { LOTTIE_URLS } from '../constants';
import { speak, startRecognition, compareText } from '../services/speechService';
import { ExerciseType } from '../types';

const ChildPlay: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<'welcome' | 'playing' | 'reward'>('welcome');
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [exerciseIndex, setExerciseIndex] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [feedback, setFeedback] = useState('');

  const exercises = [
    { 
      type: ExerciseType.ARTICULATION, 
      content: 'Mira el perrito y di: "Guau"', 
      target: 'guau', 
      imageUrl: 'https://images.unsplash.com/photo-1543466835-00a7907e9de1?w=600&h=450&fit=crop' 
    },
    { 
      type: ExerciseType.VOCABULARY, 
      content: '¿Qué fruta es esta?', 
      target: 'manzana', 
      imageUrl: 'https://images.unsplash.com/photo-1570913149827-d2ac84ab3f9a?w=600&h=450&fit=crop' 
    },
    { 
      type: ExerciseType.COMPREHENSION, 
      content: '¿Qué animal vuela por el cielo?', 
      target: 'pájaro', 
      options: ['pájaro', 'pez', 'león'],
      imageUrl: 'https://images.unsplash.com/photo-1444464666168-49d633b867ad?w=600&h=450&fit=crop'
    }
  ];

  const currentExercise = exercises[exerciseIndex];

  const handleStart = () => {
    setCurrentStep('playing');
    setMascotState(LOTTIE_URLS.mascot_idle);
    speak("¡Hola! ¿Jugamos?");
  };

  const handleListen = () => {
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('¡Te escucho!');

    const recognition = startRecognition(
      (result) => {
        setIsListening(false);
        const similarity = compareText(result, currentExercise.target);
        if (similarity > 0.5) handleSuccess();
        else handleRepeat();
      },
      () => {
        setIsListening(false);
        setFeedback('¿Otra vez?');
      }
    );
  };

  const handleSuccess = () => {
    setMascotState(LOTTIE_URLS.mascot_celebrate);
    setFeedback('¡MUY BIEN!');
    speak("¡Excelente trabajo!");
    setTimeout(() => {
      if (exerciseIndex < exercises.length - 1) {
        setExerciseIndex(idx => idx + 1);
        setMascotState(LOTTIE_URLS.mascot_idle);
        setFeedback('');
      } else setCurrentStep('reward');
    }, 2000);
  };

  const handleRepeat = () => {
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('¡Casi!');
    speak("Inténtalo de nuevo");
    setTimeout(() => {
        setFeedback('');
        setMascotState(LOTTIE_URLS.mascot_idle);
    }, 1500);
  };

  return (
    <Layout role="child">
      <div className="h-full flex flex-col items-center justify-between">

        {/* Progreso Compacto */}
        <div className="w-full max-w-md pt-2">
           <div className="h-4 bg-white/50 rounded-full border-2 border-white shadow-lg overflow-hidden relative">
              <motion.div 
                className="h-full bg-gradient-to-r from-yellow-400 to-green-500"
                initial={{ width: 0 }}
                animate={{ width: `${((exerciseIndex + 1) / exercises.length) * 100}%` }}
              />
           </div>
        </div>

        <div className="flex-1 w-full flex items-center justify-center p-2 min-h-0">
          <AnimatePresence mode="wait">
            {currentStep === 'welcome' && (
              <motion.div key="welcome" initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="text-center bg-white/60 backdrop-blur-md p-8 md:p-12 rounded-[3rem] border-4 border-white shadow-2xl max-h-full overflow-hidden">
                <div className="h-40 md:h-64 mb-6">
                  <LottiePlayer url={LOTTIE_URLS.mascot_happy} className="h-full" />
                </div>
                <h2 className="text-4xl md:text-5xl font-black text-blue-900 mb-6 uppercase">¡HOLA! ✨</h2>
                <motion.button 
                  whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                  onClick={handleStart}
                  className="bg-yellow-400 text-blue-900 text-3xl md:text-4xl font-black px-12 py-6 rounded-full shadow-[0_8px_0_#ca8a04] border-4 border-white"
                >
                  ¡EMPEZAR!
                </motion.button>
              </motion.div>
            )}

            {currentStep === 'playing' && (
              <motion.div key="playing" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="grid grid-rows-[1fr_auto] md:grid-rows-none md:grid-cols-2 gap-4 md:gap-8 h-full w-full max-w-6xl items-center">

                {/* Card de Actividad - Altura Controlada */}
                <div className="bg-white p-4 md:p-6 rounded-[2.5rem] shadow-xl border-[10px] border-blue-50 text-center flex flex-col h-full max-h-[60vh] md:max-h-[75vh]">
                  <div className="flex-1 min-h-0 mb-4 rounded-3xl overflow-hidden bg-gray-50 border-2 border-gray-100">
                    <img src={currentExercise.imageUrl} className="w-full h-full object-cover" alt="Juego" />
                  </div>

                  <h3 className="text-xl md:text-3xl font-black text-blue-900 leading-tight mb-4 px-2">
                    {currentExercise.content}
                  </h3>

                  {currentExercise.options && (
                    <div className="grid grid-cols-3 gap-2 px-2 pb-2">
                      {currentExercise.options.map(opt => (
                        <motion.button 
                          key={opt} 
                          onClick={() => opt === currentExercise.target ? handleSuccess() : handleRepeat()} 
                          className="bg-blue-100 p-3 rounded-2xl font-black text-blue-700 text-sm md:text-xl hover:bg-blue-500 hover:text-white transition-all shadow-sm"
                        >
                          {opt}
                        </motion.button>
                      ))}
                    </div>
                  )}
                </div>

                {/* Personaje y Controles */}
                <div className="flex flex-col items-center justify-center space-y-4 h-full">
                  <div className="h-40 md:h-72 aspect-square flex items-center justify-center">
                    <LottiePlayer url={mascotState} className="h-full" />
                  </div>

                  <div className="flex items-center gap-6">
                    <motion.button 
                      whileHover={{ scale: 1.1 }}
                      onClick={() => speak(currentExercise.content)}
                      className="bg-blue-500 w-16 h-16 md:w-20 md:h-20 rounded-2xl text-3xl flex items-center justify-center text-white shadow-lg border-4 border-blue-300"
                    >
                      🔊
