                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: idx * 0.05 }}
                className="bg-white border-2 border-slate-100 rounded-[2rem] shadow-sm hover:shadow-xl transition-all p-6 relative overflow-hidden group flex flex-col"
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="w-12 h-12 bg-blue-100 rounded-2xl flex items-center justify-center text-blue-600 text-2xl font-black">
                    {child.name[0]}
                  </div>
                  <span className={`text-[10px] font-black uppercase px-3 py-1 rounded-full border ${
                    child.level === Level.BASIC ? 'bg-green-50 text-green-700 border-green-200' : 'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {child.level}
                  </span>
                </div>

                <h3 className="text-2xl font-black text-blue-950 mb-1">{child.name}</h3>
                <p className="text-sm text-gray-400 font-bold mb-4">{child.characteristics}</p>

                <div className="mt-auto pt-4 border-t flex items-center justify-between">
