                      <span>⭐</span> {child.stars}
                   </div>
                   <div className="flex gap-2">
                      <button onClick={() => goTo(`/child/${child.id}/play`)} className="bg-green-500 text-white px-4 py-2 rounded-xl text-xs font-black shadow-md">JUGAR</button>
                      <button onClick={() => goTo(`/progress/${child.id}`)} className="bg-blue-50 text-blue-600 px-4 py-2 rounded-xl text-xs font-black border border-blue-100">INFO</button>
                   </div>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </div>
    </Layout>
  );
};

