const ChildPlay: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<'welcome' | 'playing' | 'reward'>('welcome');
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [exerciseIndex, setExerciseIndex] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [feedback, setFeedback] = useState('');
  const [showConfetti, setShowConfetti] = useState(false);
  const [showSkip, setShowSkip] = useState(false);

  const exercises = [
    { 
      type: ExerciseType.ARTICULATION, 
      content: 'Mira el perrito y di: "Guau"', 
      target: 'guau', 
      imageUrl: 'https://images.unsplash.com/photo-1543466835-00a7907e9de1?w=600&h=450&fit=crop' 
    },
    { 
      type: ExerciseType.VOCABULARY, 
      content: '¿Qué fruta es esta?', 
      target: 'manzana', 
      imageUrl: 'https://images.unsplash.com/photo-1570913149827-d2ac84ab3f9a?w=600&h=450&fit=crop' 
    },
