        setExerciseIndex(idx => idx + 1);
        setMascotState(LOTTIE_URLS.mascot_idle);
        setFeedback('');
      } else {
        setShowConfetti(true);
        setCurrentStep('reward');
      }
    }, 2000);
  };

  const handleRepeat = () => {
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('¡Casi!');
    setShowSkip(true); // Mostrar botón saltar si hay dificultad
    speak("Inténtalo de nuevo o pulsa la varita");
    setTimeout(() => {
        setFeedback('');
        setMascotState(LOTTIE_URLS.mascot_idle);
    }, 1500);
  };

  // Función para avanzar cuando no pueda con la actividad
  const handleSkipMagic = () => {
    setMascotState(LOTTIE_URLS.mascot_happy);
    setFeedback('¡Magia!');
    speak("¡Usamos magia para avanzar!");
    setTimeout(() => {
        handleSuccess();
    }, 1000);
