              className="absolute inset-0 z-[100] pointer-events-none"
            >
              <LottiePlayer url={LOTTIE_URLS.confetti} className="w-full h-full scale-110" />
            </motion.div>
          )}
        </AnimatePresence>

        {/* Progreso Compacto */}
        <div className="w-full max-w-md pt-2 px-4">
           <div className="h-4 bg-white/50 rounded-full border-2 border-white shadow-lg overflow-hidden relative">
