                      disabled={isListening} 
                      className={`w-24 h-24 md:w-32 md:h-32 rounded-full text-5xl flex items-center justify-center text-white shadow-2xl border-[8px] transition-all ${isListening ? 'bg-red-500 animate-pulse border-red-200' : 'bg-green-500 border-green-200'}`}
                    >
                      {isListening ? '🛑' : '🎤'}
                    </motion.button>
                  </div>

                  <AnimatePresence>
                    {feedback && (
                      <motion.div 
                        initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }}
