                      >
                        {feedback}
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              </motion.div>
            )}

            {currentStep === 'reward' && (
              <motion.div 
                key="reward" 
                initial={{ scale: 0.5, opacity: 0 }} 
                animate={{ scale: 1, opacity: 1 }} 
                className="bg-white p-8 md:p-12 rounded-[4rem] text-center shadow-2xl border-[12px] border-white max-w-md relative z-[110]"
