      imageUrl: 'https://images.unsplash.com/photo-1444464666168-49d633b867ad?w=800&q=80'
    }
  ];

  const currentExercise = exercises[exerciseIndex];

  // Temporizador para detectar si el niño pierde la atención
  useEffect(() => {
    if (currentStep !== 'playing') return;
    const idleTimer = setTimeout(() => setIsIdle(true), 8000);
    return () => {
      clearTimeout(idleTimer);
      setIsIdle(false);
    };
  }, [exerciseIndex, currentStep, isListening]);

  const handleStart = () => {
    setCurrentStep('playing');
    setShowSkip(false);
    setMascotState(LOTTIE_URLS.mascot_idle);
    speak("¡Hola! ¿Estás listo? ¡Vamos a jugar!");
  };

  const handleListen = useCallback(() => {
    if (isListening) return;

    setIsListening(true);
    setIsIdle(false);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('¡Te escucho!');

    startRecognition(
      (result) => {
        setIsListening(false);
        const similarity = compareText(result, currentExercise.target);
        if (similarity > 0.5) handleSuccess();
        else handleRepeat();
      },
      () => {
        setIsListening(false);
        setFeedback('¡Intenta otra vez!');
      }
    );
  }, [currentExercise, isListening]);

  const handleSuccess = () => {
    setMascotState(LOTTIE_URLS.mascot_celebrate);
    setFeedback('¡EXCELENTE! ⭐');
    setShowSkip(false);
    speak("¡Muy bien hecho!");

    setTimeout(() => {
      if (exerciseIndex < exercises.length - 1) {
        setExerciseIndex(idx => idx + 1);
        setMascotState(LOTTIE_URLS.mascot_idle);
        setFeedback('');
      } else {
        setShowConfetti(true);
        setCurrentStep('reward');
        speak("¡Felicidades! ¡Has ganado!");
      }
    }, 2500);
  };

  const handleRepeat = () => {
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('¡Casi lo tienes!');
    setShowSkip(true); 
    speak("¿Lo decimos otra vez?");
    setTimeout(() => {
        setFeedback('');
    }, 2000);
  };

  const handleSkipMagic = () => {
    setShowSkip(false);
    setMascotState(LOTTIE_URLS.mascot_happy);
    setFeedback('¡MAGIA! ✨');
    speak("¡Siguiente actividad!");
    setTimeout(() => {
        handleSuccess();
