                className="h-full bg-gradient-to-r from-yellow-400 via-orange-400 to-green-400 rounded-full"
                initial={{ width: 0 }}
                animate={{ width: `${((exerciseIndex + 1) / exercises.length) * 100}%` }}
                transition={{ type: "spring", stiffness: 50 }}
              />
              <div className="absolute inset-0 flex items-center justify-center">
                 <span className="text-[10px] font-black text-blue-900 uppercase tracking-tighter drop-shadow-sm">
                   Nivel {exerciseIndex + 1} de {exercises.length}
                 </span>
              </div>
           </div>
        </div>

        <div className="flex-1 w-full flex items-center justify-center p-4 min-h-0">
          <AnimatePresence mode="wait">
            {currentStep === 'welcome' && (
              <motion.div 
                key="welcome" 
                initial={{ scale: 0.5, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                className="text-center bg-white/80 backdrop-blur-xl p-10 md:p-16 rounded-[4rem] border-[12px] border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] flex flex-col items-center"
              >
                <div className="h-48 md:h-72 w-48 md:w-72 mb-8 bg-blue-50 rounded-full p-4 border-4 border-blue-100 shadow-inner">
                  <LottiePlayer url={LOTTIE_URLS.mascot_happy} className="h-full" />
