                  whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
                  onClick={handleStart}
                  className="bg-yellow-400 text-blue-950 text-3xl md:text-4xl font-black px-16 py-8 rounded-[2.5rem] shadow-[0_12px_0_#ca8a04] border-4 border-white active:translate-y-2 active:shadow-none transition-all"
                >
                  ¡SÍ, VAMOS!
                </motion.button>
              </motion.div>
