export const speak = (text: string) => {
  if (!('speechSynthesis' in window)) return;

  // Cancelar cualquier discurso previo para evitar superposiciones
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'es-ES';
  utterance.rate = 0.8; // Más lento para mejor comprensión
  utterance.pitch = 1.2; // Tono un poco más agudo/amigable para niños
  utterance.volume = 1.0;

  window.speechSynthesis.speak(utterance);
};

export const startRecognition = (onResult: (result: string) => void, onError: (err: any) => void) => {
  const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
  if (!SpeechRecognition) {
    onError("Browser doesn't support Speech Recognition");
    return null;
  }

  const recognition = new SpeechRecognition();
  recognition.lang = 'es-ES';
  recognition.interimResults = false;
  recognition.maxAlternatives = 1;
  recognition.continuous = false; // Detener tras un resultado para evitar ruido

  recognition.onresult = (event: any) => {
    const result = event.results[0][0].transcript;
    onResult(result);
  };

  recognition.onerror = (event: any) => {
    console.error("Speech Recognition Error:", event.error);
    onError(event.error);
  };

  try {
    recognition.start();
  } catch (e) {
    console.warn("Recognition already started");
  }

  return recognition;
};

export const compareText = (input: string, target: string): number => {
  const normalize = (str: string) => str.toLowerCase().trim().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[.,/#!$%^&*;:{}=\-_`~()]/g, "");
  const s1 = normalize(input);
  const s2 = normalize(target);

  if (s1 === s2) return 1;

  // Aceptamos coincidencias parciales si la palabra objetivo es corta
  if (s1.includes(s2) || s2.includes(s1)) return 0.8;

  return 0.2;
};

