import React, { useEffect, useRef, useState, memo } from 'react';

interface LottiePlayerProps {
  url: string;
  loop?: boolean;
  autoplay?: boolean;
  className?: string;
  animationData?: any;
  isSticker?: boolean; 
}

const LottiePlayer: React.FC<LottiePlayerProps> = ({ 
  url, 
  loop = true, 
  autoplay = true, 
  className = "", 
  animationData,
  isSticker = true 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [hasError, setHasError] = useState(false);
  const animRef = useRef<any>(null);

  useEffect(() => {
    let isMounted = true;

    const loadLottie = async () => {
      if (!url && !animationData) {
        setHasError(true);
        return;
      }

      try {
        setHasError(false); 
        const lottie = (await import('lottie-web')).default;

        if (containerRef.current && isMounted) {
          if (animRef.current) animRef.current.destroy();

          animRef.current = lottie.loadAnimation({
            container: containerRef.current,
            renderer: 'svg',
            loop,
            autoplay,
            path: animationData ? undefined : url,
            animationData: animationData,
            rendererSettings: {
              preserveAspectRatio: 'xMidYMid slice',
              className: 'lottie-svg-element'
            }
          });

          // Detector de fallos en la carga
          animRef.current.addEventListener('data_failed', () => {
            if (isMounted) {
              setHasError(true);
              console.warn("Lottie data_failed trigger for:", url);
            }
          });

          animRef.current.addEventListener('error', (e: any) => {
            if (isMounted) {
              setHasError(true);
              console.error("Lottie generic error:", e);
            }
          });

          animRef.current.addEventListener('DOMLoaded', () => {
            if (isMounted) setHasError(false);
          });
        }
      } catch (error) {
        if (isMounted) {
          setHasError(true);
          console.error("Lottie loader exception:", error);
        }
      }
    };

    loadLottie();

    return () => {
      isMounted = false;
      if (animRef.current) animRef.current.destroy();
    };
  }, [url, animationData, loop, autoplay]);

  if (hasError) {
    return (
      <div 
        className={`${className} bg-white/60 backdrop-blur-sm rounded-full flex items-center justify-center text-7xl shadow-inner border-4 border-white transition-all duration-500 ${isSticker ? 'lottie-sticker' : ''}`}
        style={{ minWidth: '160px', minHeight: '160px' }}
      >
        <div className="animate-bounce">
          <span className="drop-shadow-lg filter grayscale-0" role="img" aria-label="magic-fallback">✨</span>
        </div>
      </div>
    );
  }

  const drawingClasses = `lottie-2d-drawing ${isSticker ? 'lottie-sticker' : ''}`;

  return (
    <div 
      ref={containerRef} 
      className={`${className} ${drawingClasses} outline-none transition-transform duration-300 flex items-center justify-center min-h-[120px]`} 
    />
  );
};

export default memo(LottiePlayer);

