  animate: {
    opacity: 1,
    x: 0,
    scale: 1,
    transition: {
      x: { type: "spring", stiffness: 300, damping: 30 },
      opacity: { duration: 0.4 },
      scale: { duration: 0.4 }
    }
  },
  exit: (direction: number) => ({
    opacity: 0,
    x: direction < 0 ? 300 : -300,
    scale: 0.95,
    transition: { duration: 0.3 }
  })
};

