import { GoogleGenAI } from "@google/genai";
import { ExerciseType, Level, RewardTrigger } from "../types";

export const generateStreamingExercise = async (
  type: ExerciseType,
  level: Level,
  topic: string,
  config: { duration: number; repetitions: number; reward: RewardTrigger },
  onChunk: (chunk: string) => void
) => {
  const apiKey = process.env.API_KEY || "";

  const prompt = `Actúa como terapeuta de lenguaje experto en gamificación. 
  Genera un ejercicio infantil de ${type} nivel ${level} sobre el tema "${topic}".
  Configuración técnica solicitada:
  - Duración estimada: ${config.duration} minutos.
  - Repeticiones recomendadas: ${config.repetitions}.
  - Recompensa al finalizar: ${config.reward}.

  Responde ÚNICAMENTE con un objeto JSON (sin markdown) que tenga esta estructura exacta:
  {
    "content": "Instrucción clara para el niño",
    "target": "palabra o frase objetivo",
    "hint": "pista amigable para el niño",
    "image_keyword": "término en inglés para buscar una ilustración relacionada",
    "pedagogical_note": "breve nota para el terapeuta sobre por qué este ejercicio funciona con ${config.repetitions} repeticiones"
  }`;

  try {
    if (!apiKey) throw new Error("API_KEY_MISSING");

    const ai = new GoogleGenAI({ apiKey });
    const responseStream = await ai.models.generateContentStream({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        temperature: 0.8,
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      const text = chunk.text;
      if (text) {
        fullText += text;
        onChunk(fullText);
      }
    }
    return fullText;
  } catch (error: any) {
    console.warn("AI Connection Error - Switching to Mock Mode:", error.message);

    const mockResponses: Record<string, string> = {
      "Articulación": `{"content": "Mira al gatito y di: Miau", "target": "miau", "hint": "¡Como los mininos!", "image_keyword": "cat", "pedagogical_note": "Repetir ${config.repetitions} veces ayuda a fijar el fonema labial."}`,
      "Vocabulario": `{"content": "¿Cómo se llama este transporte?", "target": "cohete", "hint": "Viaja a las estrellas", "image_keyword": "rocket", "pedagogical_note": "Ideal para una sesión de ${config.duration} min."}`,
      "Comprensión": `{"content": "¿Dónde viven los peces?", "target": "agua", "hint": "Es azul y fresca", "image_keyword": "ocean", "pedagogical_note": "Usar ${config.reward} motiva la respuesta reflexiva."}`,
      "Oraciones": `{"content": "El perro come su...", "target": "hueso", "hint": "Es blanco y duro", "image_keyword": "bone", "pedagogical_note": "Estructura simple para nivel ${level}."}`
    };

    const mock = mockResponses[type] || mockResponses["Articulación"];

    for (let i = 0; i <= mock.length; i++) {
      await new Promise(r => setTimeout(r, 8));
      onChunk(mock.substring(0, i));
    }
    return mock;
  }
};

