import React, { useEffect, useRef, useState, memo } from 'react';

interface LottiePlayerProps {
  url: string;
  loop?: boolean;
  autoplay?: boolean;
  className?: string;
  animationData?: any;
  isSticker?: boolean; 
}

const LottiePlayer: React.FC<LottiePlayerProps> = ({ 
  url, 
  loop = true, 
  autoplay = true, 
  className = "", 
  animationData,
  isSticker = true 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [hasError, setHasError] = useState(false);
  const animRef = useRef<any>(null);

  useEffect(() => {
    let isMounted = true;

    const loadLottie = async () => {
      if (!url && !animationData) {
        setHasError(true);
        return;
      }

      try {
        const lottie = (await import('lottie-web')).default;

        if (containerRef.current && isMounted) {
          if (animRef.current) animRef.current.destroy();

          animRef.current = lottie.loadAnimation({
            container: containerRef.current,
            renderer: 'svg',
            loop,
            autoplay,
            path: animationData ? undefined : url,
            animationData: animationData,
            rendererSettings: {
              preserveAspectRatio: 'xMidYMid slice',
              className: 'lottie-svg-element'
            }
          });

          // Detector de fallos específico solicitado por el usuario
          animRef.current.addEventListener('data_failed', () => {
            if (isMounted) setHasError(true);
          });

          animRef.current.addEventListener('error', () => {
            if (isMounted) setHasError(true);
          });

          animRef.current.addEventListener('DOMLoaded', () => {
            if (isMounted) setHasError(false);
          });
        }
      } catch (error) {
        if (isMounted) setHasError(true);
      }
    };

    loadLottie();

    return () => {
      isMounted = false;
      if (animRef.current) animRef.current.destroy();
    };
  }, [url, animationData, loop, autoplay]);

  // Si hay error en la carga de Lottie, mostramos un fallback amigable con estética de la app
  if (hasError) {
    const fallbackEmoji = url.includes('confetti') ? '🎉' : 
                         url.includes('star') ? '⭐' : 
                         url.includes('mascot') ? '🐶' : '✨';

    return (
      <div 
        className={`${className} flex items-center justify-center`}
        style={{ minHeight: '100px' }}
      >
        <div className="bg-white/80 p-6 rounded-full shadow-xl border-4 border-yellow-200 animate-bounce text-6xl lottie-sticker">
          {fallbackEmoji}
        </div>
      </div>
    );
  }

  const drawingClasses = `lottie-2d-drawing ${isSticker ? 'lottie-sticker' : ''}`;

  return (
    <div 
      ref={containerRef} 
      className={`${className} ${drawingClasses} outline-none flex items-center justify-center`} 
    />
  );
};

