const screenVariants = {
  initial: (direction: number) => ({
    opacity: 0,
    x: direction > 0 ? 500 : -500,
    rotateY: direction > 0 ? 45 : -45
  }),
  animate: {
    opacity: 1,
    x: 0,
    rotateY: 0,
    transition: { type: "spring", stiffness: 200, damping: 20 }
  },
  exit: (direction: number) => ({
    opacity: 0,
    x: direction < 0 ? 500 : -500,
    rotateY: direction < 0 ? 45 : -45,
    transition: { duration: 0.3 }
  })
};

const ChildPlay: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<'welcome' | 'playing' | 'reward'>('welcome');
  const [direction, setDirection] = useState(1);
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [exerciseIndex, setExerciseIndex] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [feedback, setFeedback] = useState('');
  const [showConfetti, setShowConfetti] = useState(false);
  const [isIdle, setIsIdle] = useState(false);

  const idleTimerRef = useRef<number | null>(null);

  const exercises = [
    { 
      type: ExerciseType.ARTICULATION, 
      content: 'Mira el perrito y di: "Guau"', 
      target: 'guau', 
      imageUrl: 'https://images.unsplash.com/photo-1543466835-00a7907e9de1?w=800&q=80' 
    },
    { 
      type: ExerciseType.VOCABULARY, 
      content: '¿Qué fruta es esta?', 
      target: 'manzana', 
      imageUrl: 'https://images.unsplash.com/photo-1570913149827-d2ac84ab3f9a?w=800&q=80' 
    },
    { 
      type: ExerciseType.COMPREHENSION, 
      content: '¿Qué animal vuela?', 
      target: 'pájaro', 
      options: ['pájaro', 'pez', 'león'],
      imageUrl: 'https://images.unsplash.com/photo-1444464666168-49d633b867ad?w=800&q=80'
    }
  ];

  const currentExercise = exercises[exerciseIndex];

  // Gestión de atención / Inactividad
  const resetIdleTimer = useCallback(() => {
    setIsIdle(false);
    if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    idleTimerRef.current = window.setTimeout(() => {
      if (currentStep === 'playing' && !isListening) setIsIdle(true);
    }, 8000);
  }, [currentStep, isListening]);

  useEffect(() => {
    resetIdleTimer();
    return () => { if (idleTimerRef.current) clearTimeout(idleTimerRef.current); };
  }, [exerciseIndex, currentStep, isListening, resetIdleTimer]);

  const handleStart = () => {
    setDirection(1);
    setCurrentStep('playing');
    setMascotState(LOTTIE_URLS.mascot_idle);
    speak("¡Hola! ¿Estás listo? ¡Vamos a jugar!");
  };

  const handleListen = useCallback(() => {
    if (isListening) return;
    resetIdleTimer();
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('¡Te escucho! 👂');

    startRecognition(
      (result) => {
        setIsListening(false);
        const similarity = compareText(result, currentExercise.target);
        if (similarity > 0.6) handleSuccess();
        else handleRepeat();
      },
      () => {
        setIsListening(false);
        setFeedback('¡Inténtalo otra vez!');
      }
    );
  }, [currentExercise, isListening, resetIdleTimer]);

  const handleSuccess = () => {
    setMascotState(LOTTIE_URLS.mascot_celebrate);
    setFeedback('¡EXCELENTE! ⭐');
    speak("¡Muy bien hecho!");

    setTimeout(() => {
      if (exerciseIndex < exercises.length - 1) {
        setDirection(1);
        setExerciseIndex(idx => idx + 1);
        setMascotState(LOTTIE_URLS.mascot_idle);
        setFeedback('');
      } else {
        setDirection(1);
        setShowConfetti(true);
        setCurrentStep('reward');
        speak("¡Felicidades! ¡Eres un campeón!");
      }
    }, 2000);
  };

  const handleRepeat = () => {
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedback('¡Casi lo tienes! 🔄');
    speak("¿Lo intentamos de nuevo?");
    setTimeout(() => setFeedback(''), 2000);
  };

