                initial={{ width: 0 }}
                animate={{ width: `${((exerciseIndex + 1) / exercises.length) * 100}%` }}
              />
           </div>
        </div>

        <div className="flex-1 w-full flex items-center justify-center p-4">
          <AnimatePresence mode="wait" custom={direction}>
            {currentStep === 'welcome' && (
              <motion.div 
                key="welcome"
                custom={direction}
                variants={screenVariants}
                initial="initial"
                animate="animate"
                exit="exit"
                className="text-center bg-white/90 backdrop-blur-xl p-12 rounded-[4rem] border-[12px] border-white shadow-2xl flex flex-col items-center max-w-lg w-full"
              >
                <LottiePlayer url={LOTTIE_URLS.mascot_happy} className="h-64 w-64 mb-8" />
                <h2 className="text-5xl font-black text-blue-900 mb-8 uppercase">¡HOLA AMIGO!</h2>
                <motion.button 
                  whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
                  onClick={handleStart}
                  className="bg-yellow-400 text-blue-900 text-4xl font-black px-16 py-8 rounded-[3rem] shadow-[0_12px_0_#ca8a04] border-4 border-white active:translate-y-2 active:shadow-none transition-all"
                >
                  ¡A JUGAR!
                </motion.button>
              </motion.div>
            )}

            {currentStep === 'playing' && (
              <motion.div 
                key={`playing-${exerciseIndex}`}
                custom={direction}
                variants={screenVariants}
                initial="initial"
                animate="animate"
                exit="exit"
                className="grid md:grid-cols-2 gap-8 h-full w-full max-w-7xl items-center"
              >
                {/* Panel Visual */}
                <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl border-[15px] border-blue-50 text-center flex flex-col h-full max-h-[75vh]">
                  <div className="flex-1 min-h-0 mb-6 rounded-[2.5rem] overflow-hidden border-4 border-slate-50 shadow-inner">
                    <motion.img 
                      key={currentExercise.imageUrl}
                      initial={{ scale: 1.2, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                      src={currentExercise.imageUrl} 
                      className="w-full h-full object-cover" 
