export const speak = (text: string) => {
  if (!('speechSynthesis' in window)) return;

  try {
    // Cancelar cualquier discurso previo para evitar superposiciones
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'es-ES';
    utterance.rate = 0.85; // Velocidad óptima para claridad infantil
    utterance.pitch = 1.3;  // Tono ligeramente más agudo para sonar amigable/infantil
    utterance.volume = 1.0;

    window.speechSynthesis.speak(utterance);
  } catch (err) {
    console.error("Speech Synthesis error:", err);
  }
};

export const startRecognition = (onResult: (result: string) => void, onError: (err: any) => void) => {
  const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

  if (!SpeechRecognition) {
    onError("Browser doesn't support Speech Recognition");
    return null;
  }

  try {
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;
    recognition.continuous = false;

    recognition.onresult = (event: any) => {
      if (event.results && event.results.length > 0) {
        const result = event.results[0][0].transcript;
        console.log("Recognition result:", result);
        onResult(result);
      }
    };

    recognition.onerror = (event: any) => {
      console.warn("Speech Recognition error:", event.error);
      onError(event.error);
    };

    recognition.onend = () => {
      console.log("Recognition session ended");
    };

    recognition.start();
    return recognition;
  } catch (e) {
    console.error("Recognition initialization failed:", e);
    onError(e);
    return null;
  }
};

export const compareText = (input: string, target: string): number => {
  const normalize = (str: string) => 
    str.toLowerCase()
       .trim()
       .normalize("NFD")
       .replace(/[\u0300-\u036f]/g, "")
       .replace(/[.,/#!$%^&*;:{}=\-_`~()]/g, "");

  const s1 = normalize(input);
  const s2 = normalize(target);

  if (s1 === s2) return 1;

  // Lógica de coincidencia parcial para mayor tolerancia con niños
  const words1 = s1.split(/\s+/);
  const words2 = s2.split(/\s+/);

  const matches = words1.filter(w => words2.some(tw => tw.includes(w) || w.includes(tw)));
  const score = matches.length / Math.max(words1.length, words2.length);

  // Si contiene la palabra clave principal, damos un empujón al puntaje
  if (s1.includes(s2) || s2.includes(s1)) return Math.max(score, 0.8);

  return score;
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Layout from '../components/Layout';
import { motion, AnimatePresence } from 'framer-motion';
import LottiePlayer from '../components/LottiePlayer';
import { LOTTIE_URLS } from '../constants';
import { speak, startRecognition, compareText } from '../services/speechService';
import { ExerciseType } from '../types';

type PlayStep = 'welcome' | 'selection' | 'playing' | 'feedback' | 'reward';

const screenVariants = {
  initial: (direction: number) => ({
    opacity: 0,
    x: direction > 0 ? 800 : -800,
    rotateY: direction > 0 ? 45 : -45,
    scale: 0.9
  }),
  animate: {
    opacity: 1,
    x: 0,
    rotateY: 0,
    scale: 1,
    transition: { type: "spring", stiffness: 100, damping: 20 }
  },
  exit: (direction: number) => ({
    opacity: 0,
    x: direction < 0 ? 800 : -800,
    rotateY: direction < 0 ? 45 : -45,
    scale: 0.9,
    transition: { duration: 0.4 }
  })
};

const ChildPlay: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<PlayStep>('welcome');
  const [selectedModule, setSelectedModule] = useState<ExerciseType | null>(null);
  const [direction, setDirection] = useState(1);
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [exerciseIndex, setExerciseIndex] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [feedbackMsg, setFeedbackMsg] = useState('');
  const [showConfetti, setShowConfetti] = useState(false);
  const [isIdle, setIsIdle] = useState(false);
  const idleTimerRef = useRef<number | null>(null);

  // Mock de ejercicios filtrados por tipo
  const allExercises = [
    { type: ExerciseType.ARTICULATION, content: 'Di: "Rrrra-na"', target: 'rana', imageUrl: 'https://images.unsplash.com/photo-1594498653385-d5172b532c00?w=500' },
    { type: ExerciseType.VOCABULARY, content: '¿Qué fruta es esta?', target: 'pera', imageUrl: 'https://images.unsplash.com/photo-1514810771018-276192729582?w=500' },
    { type: ExerciseType.COMPREHENSION, content: '¿Quién vive en la granja?', target: 'vaca', options: ['vaca', 'pez', 'león'], imageUrl: 'https://images.unsplash.com/photo-1570042225831-d98fa7577f1e?w=500' },
    { type: ExerciseType.SENTENCES, content: 'El gato bebe...', target: 'leche', imageUrl: 'https://images.unsplash.com/photo-1514888286974-6c03e2ca1dba?w=500' }
  ];

  const filteredExercises = selectedModule 
    ? allExercises.filter(ex => ex.type === selectedModule) 
    : [allExercises[0]];

  const currentExercise = filteredExercises[exerciseIndex] || allExercises[0];

  const resetIdleTimer = useCallback(() => {
    setIsIdle(false);
    if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    idleTimerRef.current = window.setTimeout(() => {
      if (currentStep === 'playing' && !isListening) setIsIdle(true);
    }, 8000);
  }, [currentStep, isListening]);

  useEffect(() => {
    resetIdleTimer();
    if (currentStep === 'welcome') speak("¡Hola amiguito! ¿Qué quieres aprender hoy?");
    return () => { if (idleTimerRef.current) clearTimeout(idleTimerRef.current); };
  }, [currentStep, resetIdleTimer]);

  const handleModuleSelect = (type: ExerciseType) => {
    setDirection(1);
    setSelectedModule(type);
    setCurrentStep('playing');
    speak(`¡Genial! Vamos a jugar con ${type}`);
  };

  const handleListen = useCallback(() => {
    if (isListening) return;
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedbackMsg('¡Te escucho! 👂');

    startRecognition(
      (result) => {
        setIsListening(false);
        const score = compareText(result, currentExercise.target);
        if (score > 0.6) {
          handleSuccess();
        } else {
          setMascotState(LOTTIE_URLS.mascot_idle);
          setFeedbackMsg('¡Casi! Inténtalo de nuevo');
          speak("¿Lo decimos otra vez?");
        }
      },
      () => {
        setIsListening(false);
        setFeedbackMsg('¡Inténtalo otra vez!');
      }
    );
  }, [currentExercise, isListening]);

  const handleSuccess = () => {
    setMascotState(LOTTIE_URLS.mascot_celebrate);
    setFeedbackMsg('¡EXCELENTE! ⭐');
    speak("¡Muy bien hecho!");
    setTimeout(() => {
      setDirection(1);
      setCurrentStep('feedback');
    }, 1500);
  };

  const handleFeedbackResponse = (status: 'ok' | 'process' | 'repeat') => {
    setDirection(1);
    if (exerciseIndex < filteredExercises.length - 1) {
      setExerciseIndex(idx => idx + 1);
      setCurrentStep('playing');
      setMascotState(LOTTIE_URLS.mascot_idle);
      setFeedbackMsg('');
    } else {
      setShowConfetti(true);
      setCurrentStep('reward');
    }
  };

  return (
    <Layout role="child">
      <div className="h-full flex flex-col items-center justify-center relative overflow-hidden perspective-1000">

        {showConfetti && (
          <div className="absolute inset-0 z-[100] pointer-events-none">
            <LottiePlayer url={LOTTIE_URLS.confetti} className="w-full h-full" />
          </div>
        )}

        <AnimatePresence mode="wait" custom={direction}>
          {/* 1. BIENVENIDA */}
          {currentStep === 'welcome' && (
            <motion.div 
              key="welcome" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="bg-white/90 backdrop-blur-xl p-10 rounded-[4rem] border-[12px] border-white shadow-2xl flex flex-col items-center max-w-lg w-full text-center"
            >
              <LottiePlayer url={LOTTIE_URLS.mascot_happy} className="h-56 w-56 mb-6" />
              <h2 className="text-4xl font-black text-blue-900 mb-8 uppercase">¡HOLA CAMPEÓN!</h2>
              <div className="flex flex-col gap-4 w-full">
                <motion.button 
                  whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                  onClick={() => { setDirection(1); setCurrentStep('selection'); }}
                  className="bg-yellow-400 text-blue-900 text-3xl font-black py-6 rounded-3xl shadow-[0_8px_0_#ca8a04] border-4 border-white"
                >
                  ¡EMPEZAR! 🚀
                </motion.button>
                <div className="grid grid-cols-2 gap-4">
                  <button 
                    onClick={() => window.location.hash = '#/child/1/collection'}
                    className="bg-blue-500 text-white font-black py-4 rounded-2xl border-4 border-white shadow-lg text-lg"
                  >
                    ESTRELLAS ⭐
                  </button>
                  <button 
                    onClick={() => window.location.hash = '#/'}
                    className="bg-red-500 text-white font-black py-4 rounded-2xl border-4 border-white shadow-lg text-lg"
                  >
                    SALIR 🏠
                  </button>
                </div>
              </div>
            </motion.div>
          )}

          {/* 2. SELECCIÓN DE MÓDULO */}
          {currentStep === 'selection' && (
            <motion.div 
              key="selection" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="w-full max-w-5xl px-4"
            >
              <h2 className="text-4xl font-black text-white drop-shadow-lg text-center mb-10 uppercase tracking-widest">¿Qué jugamos hoy?</h2>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {[
                  { type: ExerciseType.ARTICULATION, icon: '👄', color: 'bg-orange-400', border: 'border-orange-200' },
                  { type: ExerciseType.VOCABULARY, icon: '🍎', color: 'bg-green-500', border: 'border-green-200' },
                  { type: ExerciseType.COMPREHENSION, icon: '🧠', color: 'bg-purple-500', border: 'border-purple-200' },
                  { type: ExerciseType.SENTENCES, icon: '📝', color: 'bg-blue-500', border: 'border-blue-200' }
                ].map((mod) => (
                  <motion.button
                    key={mod.type}
                    whileHover={{ scale: 1.05, rotate: 2 }}
                    whileTap={{ scale: 0.9 }}
                    onClick={() => handleModuleSelect(mod.type)}
                    className={`${mod.color} ${mod.border} border-8 aspect-square rounded-[3rem] shadow-2xl flex flex-col items-center justify-center p-6 text-white group`}
                  >
