                    <button onClick={() => speak(generatedExercise.content)} className="bg-blue-600 w-24 h-24 rounded-3xl text-4xl shadow-xl border-4 border-blue-300 text-white">🔊</button>
                    <button 
                      onClick={handleListen} disabled={isListening}
                      className={`w-36 h-36 rounded-full text-7xl flex items-center justify-center text-white border-[10px] shadow-2xl transition-all ${isListening ? 'bg-red-500 border-red-200 animate-pulse scale-110' : 'bg-green-500 border-green-200'}`}
