};

export const LOTTIE_URLS = {
  // URLs optimizadas y probadas para mayor estabilidad
  mascot_idle: 'https://fonts.gstatic.com/s/i/short-term/release/googlesymbols/pet_supplies/default/24px.svg', // Fallback visual
  mascot_happy: 'https://assets2.lottiefiles.com/packages/lf20_myejioos.json', 
