  { id: '5', name: 'Amigo Robot', image: '🤖', requirement: 150 },
];

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import Layout from '../components/Layout';
import { motion, AnimatePresence } from 'framer-motion';
import LottiePlayer from '../components/LottiePlayer';
import { LOTTIE_URLS } from '../constants';
import { speak, startRecognition, compareText } from '../services/speechService';
import { generateStreamingExercise } from '../services/geminiService';
import { ExerciseType, Level, RewardTrigger } from '../types';

type PlayStep = 'welcome' | 'selection' | 'generating' | 'playing' | 'feedback' | 'reward';

const screenVariants = {
  initial: (direction: number) => ({
    opacity: 0,
    x: direction > 0 ? 500 : -500,
    rotateY: direction > 0 ? 30 : -30,
    scale: 0.95
  }),
  animate: {
    opacity: 1,
    x: 0,
    rotateY: 0,
    scale: 1,
    transition: { type: "spring", stiffness: 120, damping: 20 }
  },
  exit: (direction: number) => ({
    opacity: 0,
    x: direction < 0 ? 500 : -500,
    rotateY: direction < 0 ? 30 : -30,
    scale: 0.95,
    transition: { duration: 0.3 }
  })
};

const ChildPlay: React.FC = () => {
  const navigate = useNavigate();
  const [currentStep, setCurrentStep] = useState<PlayStep>('welcome');
  const [selectedModule, setSelectedModule] = useState<ExerciseType | null>(null);
  const [direction, setDirection] = useState(1);
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [isListening, setIsListening] = useState(false);
  const [feedbackMsg, setFeedbackMsg] = useState('');
  const [showConfetti, setShowConfetti] = useState(false);
  const [showStars, setShowStars] = useState(false);
  const [isIdle, setIsIdle] = useState(false);
  const [generatedExercise, setGeneratedExercise] = useState<any>(null);
  const [sessionHistory, setSessionHistory] = useState<string[]>([]);

  const idleTimerRef = useRef<number | null>(null);

  const resetIdleTimer = useCallback(() => {
    setIsIdle(false);
    if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    idleTimerRef.current = window.setTimeout(() => {
      if (currentStep === 'playing' && !isListening) setIsIdle(true);
    }, 10000);
  }, [currentStep, isListening]);

  useEffect(() => {
    resetIdleTimer();
    if (currentStep === 'welcome') speak("¡Hola amiguito! ¿Qué quieres aprender hoy?");
    return () => { if (idleTimerRef.current) clearTimeout(idleTimerRef.current); };
  }, [currentStep, resetIdleTimer]);

  const fetchNewExercise = async (type: ExerciseType) => {
    setCurrentStep('generating');
    setMascotState(LOTTIE_URLS.mascot_encourage);

    const childTopics = [
      "animales de la selva", "el espacio sideral", "frutas de colores", 
      "juguetes de madera", "instrumentos musicales", "cohetes rápidos", 
      "peces bajo el mar", "perritos felices", "el arcoiris"
    ];

    const randomTopic = childTopics[Math.floor(Math.random() * childTopics.length)];
    const config = { duration: 5, repetitions: 3, reward: RewardTrigger.STARS };

    try {
      const result = await generateStreamingExercise(type, Level.BASIC, randomTopic, config, () => {});
      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0].trim());
        // URL de imagen mejorada con Unsplash para mayor calidad
        const query = encodeURIComponent(`${parsed.image_keyword || parsed.target},cartoon,drawing`);
        parsed.imageUrl = `https://loremflickr.com/800/600/${query}/all?lock=${Math.floor(Math.random()*1000)}`;

        setTimeout(() => {
          setGeneratedExercise(parsed);
          setCurrentStep('playing');
          setMascotState(LOTTIE_URLS.mascot_happy);
          setSessionHistory(prev => [...prev, parsed.target]);
          speak(parsed.content);
        }, 1800);
      }
    } catch (e) {
      console.error("Error generating exercise:", e);
      setCurrentStep('selection');
    }
  };

  const handleModuleSelect = (type: ExerciseType) => {
    setDirection(1);
    setSelectedModule(type);
    fetchNewExercise(type);
  };

  const handleListen = useCallback(() => {
    if (isListening || !generatedExercise) return;
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedbackMsg('¡Te escucho! 👂');

    startRecognition(
      (result) => {
        setIsListening(false);
        const score = compareText(result, generatedExercise.target || '');
        if (score > 0.6) {
          handleSuccess();
        } else {
          setMascotState(LOTTIE_URLS.mascot_idle);
          setFeedbackMsg('¡Casi! Otra vez');
          speak("¿Lo intentamos de nuevo?");
        }
      },
      () => {
        setIsListening(false);
        setFeedbackMsg('¡Inténtalo otra vez!');
      }
    );
  }, [generatedExercise, isListening]);

  const handleSuccess = () => {
    setMascotState(LOTTIE_URLS.mascot_celebrate);
    setFeedbackMsg('¡EXCELENTE! ⭐');
    setShowStars(true); // Activar DESTELLOS
    speak("¡Lo hiciste genial! ¡Eres una super estrella!");

    setTimeout(() => {
      setShowStars(false);
      setDirection(1);
      setCurrentStep('feedback');
    }, 2500);
  };

  const handleFeedbackResponse = (status: 'ok' | 'process' | 'repeat') => {
    setDirection(1);
    if (status === 'repeat') {
      setCurrentStep('playing');
      setMascotState(LOTTIE_URLS.mascot_happy);
      setFeedbackMsg('');
      speak(generatedExercise.content);
    } else if (sessionHistory.length < 3) {
      if (selectedModule) fetchNewExercise(selectedModule);
    } else {
      setShowConfetti(true);
      setCurrentStep('reward');
    }
  };

  return (
    <Layout role="child">
      <div className="h-full flex flex-col items-center justify-center relative overflow-hidden perspective-1000">

        {showConfetti && (
          <div className="absolute inset-0 z-[100] pointer-events-none">
            <LottiePlayer url={LOTTIE_URLS.confetti} className="w-full h-full" />
          </div>
        )}

        <AnimatePresence mode="wait" custom={direction}>
          {/* 1. BIENVENIDA */}
          {currentStep === 'welcome' && (
            <motion.div 
              key="welcome" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="bg-white/95 backdrop-blur-xl p-10 rounded-[4rem] border-[12px] border-white shadow-2xl flex flex-col items-center max-w-lg w-full text-center"
            >
              <div className="w-64 h-64 mb-6">
                <LottiePlayer url={LOTTIE_URLS.mascot_happy} className="w-full h-full" />
              </div>
              <h2 className="text-4xl font-black text-blue-900 mb-8 uppercase">¡HOLA CAMPEÓN!</h2>
              <div className="flex flex-col gap-5 w-full">
                <motion.button 
                  whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                  onClick={() => { setDirection(1); setCurrentStep('selection'); }}
                  className="bg-yellow-400 text-blue-900 text-3xl font-black py-6 rounded-[2rem] shadow-[0_10px_0_#ca8a04] border-4 border-white transition-all"
                >
                  ¡EMPEZAR! 🚀
                </motion.button>
                <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => navigate(`/child/1/collection`)} className="bg-blue-500 text-white font-black py-4 rounded-2xl border-4 border-white shadow-lg text-lg">MIS PREMIOS 🎁</button>
                  <button onClick={() => navigate('/')} className="bg-red-500 text-white font-black py-4 rounded-2xl border-4 border-white shadow-lg text-lg">SALIR 🏠</button>
                </div>
              </div>
            </motion.div>
          )}

          {/* 2. SELECCIÓN DE MÓDULO */}
          {currentStep === 'selection' && (
            <motion.div 
              key="selection" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="w-full max-w-5xl px-4"
            >
              <h2 className="text-4xl font-black text-blue-900 text-center mb-10 uppercase tracking-widest drop-shadow-lg">¿Qué quieres aprender hoy?</h2>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {[
                  { type: ExerciseType.ARTICULATION, icon: '👄', color: 'bg-orange-400', border: 'border-orange-200' },
                  { type: ExerciseType.VOCABULARY, icon: '🍎', color: 'bg-green-500', border: 'border-green-200' },
                  { type: ExerciseType.COMPREHENSION, icon: '🧠', color: 'bg-purple-500', border: 'border-purple-200' },
                  { type: ExerciseType.SENTENCES, icon: '📝', color: 'bg-blue-500', border: 'border-blue-200' }
                ].map((mod) => (
                  <motion.button
                    key={mod.type}
                    whileHover={{ scale: 1.08, rotate: 2 }} whileTap={{ scale: 0.9 }}
                    onClick={() => handleModuleSelect(mod.type)}
                    className={`${mod.color} ${mod.border} border-8 aspect-square rounded-[3rem] shadow-2xl flex flex-col items-center justify-center p-6 text-white group`}
                  >
                    <span className="text-7xl mb-4 group-hover:animate-bounce">{mod.icon}</span>
                    <span className="font-black text-xl uppercase tracking-tighter">{mod.type}</span>
                  </motion.button>
                ))}
              </div>
              <button 
                onClick={() => { setDirection(-1); setCurrentStep('welcome'); }}
                className="mt-12 mx-auto block bg-white text-blue-900 font-black px-12 py-4 rounded-full border-4 border-blue-100 shadow-xl"
              >
                ← VOLVER
              </button>
            </motion.div>
          )}

          {/* 2.5 GENERANDO CON IA */}
          {currentStep === 'generating' && (
            <motion.div 
              key="generating" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="flex flex-col items-center text-center"
            >
              <div className="relative w-80 h-80 mb-8">
                 <LottiePlayer url={LOTTIE_URLS.clouds} className="w-full h-full" />
              </div>
              <h2 className="text-5xl font-black text-blue-900 animate-pulse uppercase">¡Creando magia! ✨</h2>
              <p className="text-2xl font-bold text-blue-500 mt-4 italic">Estamos dibujando algo especial para ti...</p>
            </motion.div>
          )}

          {/* 3. JUGANDO */}
          {currentStep === 'playing' && generatedExercise && (
            <motion.div 
              key="playing" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="grid lg:grid-cols-2 gap-10 w-full max-w-6xl items-center px-4"
            >
              <div className="bg-white p-6 md:p-10 rounded-[4rem] border-[12px] border-blue-50 shadow-2xl flex flex-col text-center">
                 <div className="aspect-video rounded-[2.5rem] overflow-hidden border-4 border-slate-50 mb-6 shadow-inner relative bg-blue-50">
                    <img 
                      src={generatedExercise.imageUrl} 
                      className="w-full h-full object-cover" 
                      alt="Ejercicio" 
                      onError={(e) => {
                        (e.target as HTMLImageElement).src = "https://img.freepik.com/premium-vector/cute-dog-cartoon_1033285-1.jpg";
                      }}
                    />
                 </div>
                 <h3 className="text-3xl md:text-4xl font-black text-blue-900 mb-6 leading-tight">{generatedExercise.content}</h3>

                 {selectedModule === ExerciseType.COMPREHENSION && (
                   <div className="grid grid-cols-2 gap-4">
                     {["pájaro", "pez", "perro", "gato"].map(opt => (
                       <button 
                        key={opt} onClick={() => opt.toLowerCase() === generatedExercise.target.toLowerCase() ? handleSuccess() : speak("¡Casi! Intenta de nuevo")}
                        className="bg-blue-50 border-4 border-blue-100 p-4 rounded-2xl font-black text-blue-700 text-2xl hover:bg-blue-500 hover:text-white transition-all shadow-md active:scale-95"
                       >
                         {opt}
                       </button>
                     ))}
                   </div>
                 )}
              </div>

              <div className="flex flex-col items-center gap-8 relative">
                {/* Animación de DESTELLOS sobre la mascota */}
                {showStars && (
                  <div className="absolute inset-0 z-50 pointer-events-none">
                    <LottiePlayer url={LOTTIE_URLS.stars} className="w-full h-full" />
                  </div>
                )}

                <div className={`relative transition-all duration-700 ${isIdle ? 'scale-110' : ''}`}>
                  <LottiePlayer url={mascotState} className="h-80 w-80" />
                  {isIdle && (
                    <motion.div animate={{ y: [0, -10, 0] }} transition={{ repeat: Infinity }} className="absolute -top-10 left-1/2 -translate-x-1/2 bg-yellow-400 px-8 py-3 rounded-2xl font-black border-4 border-white text-blue-900 shadow-xl text-xl">
                      ¡HÁBLAME! 👇
                    </motion.div>
                  )}
                </div>

                <div className="flex flex-col items-center gap-4 w-full">
                  {feedbackMsg && <div className="bg-yellow-400 px-8 py-3 rounded-full font-black text-blue-900 text-2xl border-4 border-white shadow-lg animate-bounce">{feedbackMsg}</div>}
                  <div className="flex gap-6">
                    <button onClick={() => speak(generatedExercise.content)} className="bg-blue-600 w-24 h-24 rounded-3xl text-4xl shadow-xl border-4 border-blue-300 text-white hover:scale-105 active:scale-90">🔊</button>
                    <button 
                      onClick={handleListen} disabled={isListening}
                      className={`w-36 h-36 rounded-full text-7xl flex items-center justify-center text-white border-[10px] shadow-2xl transition-all transform ${isListening ? 'bg-red-500 border-red-200 animate-pulse scale-110' : 'bg-green-500 border-green-200 hover:scale-105 active:scale-90'}`}
                    >
                      {isListening ? '🛑' : '🎤'}
                    </button>
                  </div>
                </div>
              </div>
            </motion.div>
          )}

          {/* 4. FEEDBACK */}
          {currentStep === 'feedback' && (
            <motion.div 
              key="feedback" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="bg-white p-12 rounded-[5rem] border-[15px] border-yellow-200 shadow-2xl text-center max-w-xl w-full"
            >
              <h2 className="text-4xl font-black text-blue-900 mb-4 uppercase">¿Cómo te fue?</h2>
              <div className="grid grid-cols-3 gap-6 mt-10">
                {[
                  { label: 'Repetir', icon: '🔄', color: 'bg-red-100 text-red-600', val: 'repeat' },
                  { label: 'En proceso', icon: '⏳', color: 'bg-blue-100 text-blue-600', val: 'process' },
                  { label: '¡Lo logré!', icon: '✅', color: 'bg-green-100 text-green-600', val: 'ok' }
                ].map(btn => (
                  <motion.button
                    key={btn.val} whileHover={{ scale: 1.15, rotate: 2 }} whileTap={{ scale: 0.9 }}
                    onClick={() => handleFeedbackResponse(btn.val as any)}
                    className={`${btn.color} p-6 rounded-[2.5rem] flex flex-col items-center gap-3 border-4 border-white shadow-lg transition-colors`}
                  >
                    <span className="text-6xl">{btn.icon}</span>
                    <span className="font-black text-sm uppercase tracking-tighter">{btn.label}</span>
                  </motion.button>
                ))}
              </div>
            </motion.div>
          )}

          {/* 5. RECOMPENSA FINAL */}
          {currentStep === 'reward' && (
            <motion.div 
              key="reward" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="bg-white p-16 rounded-[6rem] text-center shadow-2xl border-[20px] border-yellow-300 max-w-2xl w-full"
            >
              <motion.div initial={{ scale: 0 }} animate={{ scale: 1, rotate: [0, 15, -15, 0] }} transition={{ type: "spring", delay: 0.4 }} className="text-[12rem] mb-8">🏆</motion.div>
              <h2 className="text-7xl font-black text-blue-950 mb-4 uppercase leading-none">¡LO LOGRASTE!</h2>
              <button 
                onClick={() => navigate(`/child/1/collection`)}
                className="w-full bg-green-500 text-white font-black py-10 rounded-[3.5rem] text-4xl shadow-[0_15px_0_#166534] border-4 border-white transition-all"
              >
                VER MI PREMIO 🎁
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </Layout>
  );
};

