import { GoogleGenAI } from "@google/genai";
import { ExerciseType, Level, RewardTrigger } from "../types";

export const generateStreamingExercise = async (
  type: ExerciseType,
  level: Level,
  topic: string,
  config: { duration: number; repetitions: number; reward: RewardTrigger },
  onChunk: (chunk: string) => void
) => {
  const apiKey = process.env.API_KEY || "";

  const prompt = `Actúa como terapeuta de lenguaje experto en gamificación. 
  Genera un ejercicio infantil de ${type} nivel ${level} sobre el tema "${topic}".
  Configuración técnica solicitada:
  - Duración estimada: ${config.duration} minutos.
  - Repeticiones recomendadas: ${config.repetitions}.
  - Recompensa al finalizar: ${config.reward}.

  Responde ÚNICAMENTE con un objeto JSON (sin markdown) que tenga esta estructura exacta:
  {
    "content": "Instrucción clara para el niño",
    "target": "palabra o frase objetivo",
    "hint": "pista amigable para el niño",
    "image_keyword": "término en inglés para buscar una ilustración relacionada",
    "pedagogical_note": "breve nota para el terapeuta sobre por qué este ejercicio funciona con ${config.repetitions} repeticiones"
  }`;

  try {
    if (!apiKey) throw new Error("API_KEY_MISSING");

    const ai = new GoogleGenAI({ apiKey });
    const responseStream = await ai.models.generateContentStream({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        temperature: 0.8,
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      const text = chunk.text;
      if (text) {
        fullText += text;
        onChunk(fullText);
      }
    }
    return fullText;
  } catch (error: any) {
    console.warn("AI Connection Error - Switching to Mock Mode:", error.message);
    const mockResponses: Record<string, string> = {
      "Articulación": `{"content": "Mira al gatito y di: Miau", "target": "miau", "hint": "¡Como los mininos!", "image_keyword": "cute kitten", "pedagogical_note": "Repetir ${config.repetitions} veces ayuda a fijar el fonema labial."}`,
      "Vocabulario": `{"content": "¿Cómo se llama este transporte?", "target": "cohete", "hint": "Viaja a las estrellas", "image_keyword": "space rocket", "pedagogical_note": "Ideal para una sesión de ${config.duration} min."}`,
      "Comprensión": `{"content": "¿Dónde viven los peces?", "target": "agua", "hint": "Es azul y fresca", "image_keyword": "goldfish in water", "pedagogical_note": "Usar ${config.reward} motiva la respuesta reflexiva."}`,
      "Oraciones": `{"content": "El perro come su...", "target": "hueso", "hint": "Es blanco y duro", "image_keyword": "happy dog with bone", "pedagogical_note": "Estructura simple para nivel ${level}."}`
    };
    const mock = mockResponses[type] || mockResponses["Articulación"];
    for (let i = 0; i <= mock.length; i++) {
      await new Promise(r => setTimeout(r, 8));
      onChunk(mock.substring(0, i));
    }
    return mock;
  }
};

/**
 * Genera una imagen personalizada usando Gemini 2.5 Flash Image
 */
export const generateExerciseImage = async (keyword: string): Promise<string> => {
  const apiKey = process.env.API_KEY || "";
  if (!apiKey) return "https://img.freepik.com/premium-vector/cute-dog-cartoon_1033285-1.jpg";

  const ai = new GoogleGenAI({ apiKey });
  const prompt = `A simple, colorful, high-quality cartoon illustration for a children's speech therapy app. 
  Subject: ${keyword}. 
  Style: Clean lines, bright cheerful colors, friendly, no text, white background, sticker style.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: { aspectRatio: "4:3" }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return "https://img.freepik.com/premium-vector/cute-dog-cartoon_1033285-1.jpg";
  } catch (error) {
    console.error("Error generating AI image:", error);
    // Fallback a una imagen de placeholder si falla la generación
    return `https://loremflickr.com/800/600/${encodeURIComponent(keyword)},cartoon/all`;
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import Layout from '../components/Layout';
import { motion, AnimatePresence } from 'framer-motion';
import LottiePlayer from '../components/LottiePlayer';
import { LOTTIE_URLS } from '../constants';
import { speak, startRecognition, compareText } from '../services/speechService';
import { generateStreamingExercise, generateExerciseImage } from '../services/geminiService';
import { connectLiveChat, encodePCM, decodePCM, decodeAudioData } from '../services/liveApiService';
import { ExerciseType, Level, RewardTrigger } from '../types';

type PlayStep = 'welcome' | 'selection' | 'generating' | 'playing' | 'live_chat' | 'feedback' | 'reward';

const screenVariants = {
  initial: (direction: number) => ({
    opacity: 0,
    x: direction > 0 ? 500 : -500,
    rotateY: direction > 0 ? 30 : -30,
    scale: 0.95
  }),
  animate: {
    opacity: 1,
    x: 0,
    rotateY: 0,
    scale: 1,
    transition: { type: "spring", stiffness: 120, damping: 20 }
  },
  exit: (direction: number) => ({
    opacity: 0,
    x: direction < 0 ? 500 : -500,
    rotateY: direction < 0 ? 30 : -30,
    scale: 0.95,
    transition: { duration: 0.3 }
  })
};

const ChildPlay: React.FC = () => {
  const navigate = useNavigate();
  const [currentStep, setCurrentStep] = useState<PlayStep>('welcome');
  const [selectedModule, setSelectedModule] = useState<ExerciseType | null>(null);
  const [direction, setDirection] = useState(1);
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [isListening, setIsListening] = useState(false);
  const [feedbackMsg, setFeedbackMsg] = useState('');
  const [showConfetti, setShowConfetti] = useState(false);
  const [showStars, setShowStars] = useState(false);
  const [isIdle, setIsIdle] = useState(false);
  const [generatedExercise, setGeneratedExercise] = useState<any>(null);
  const [sessionHistory, setSessionHistory] = useState<string[]>([]);

  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const idleTimerRef = useRef<number | null>(null);

  const resetIdleTimer = useCallback(() => {
    setIsIdle(false);
    if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    idleTimerRef.current = window.setTimeout(() => {
      if ((currentStep === 'playing' || currentStep === 'live_chat') && !isListening) setIsIdle(true);
    }, 10000);
  }, [currentStep, isListening]);

  useEffect(() => {
    resetIdleTimer();
    if (currentStep === 'welcome') speak("¡Hola amiguito! ¿Qué quieres aprender hoy?");
    return () => { 
      if (idleTimerRef.current) clearTimeout(idleTimerRef.current); 
      stopLiveSession();
    };
  }, [currentStep, resetIdleTimer]);

  const stopLiveSession = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }
    if (audioContextInRef.current) audioContextInRef.current.close();
    if (audioContextOutRef.current) audioContextOutRef.current.close();
  };

  const startLiveChat = async () => {
    setDirection(1);
    setCurrentStep('live_chat');
    setMascotState(LOTTIE_URLS.mascot_encourage);

    const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    audioContextInRef.current = inputCtx;
    audioContextOutRef.current = outputCtx;

    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

    const sessionPromise = connectLiveChat({
      onOpen: () => {
        const source = inputCtx.createMediaStreamSource(stream);
        const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          const l = inputData.length;
          const int16 = new Int16Array(l);
          for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;
          const pcmBlob = { data: encodePCM(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
          sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
        };
        source.connect(scriptProcessor);
        scriptProcessor.connect(inputCtx.destination);
      },
      onAudioData: async (base64) => {
        setMascotState(LOTTIE_URLS.mascot_celebrate);
        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
        const buffer = await decodeAudioData(decodePCM(base64), outputCtx, 24000, 1);
        const source = outputCtx.createBufferSource();
        source.buffer = buffer;
        source.connect(outputCtx.destination);
        source.onended = () => {
          sourcesRef.current.delete(source);
          if (sourcesRef.current.size === 0) setMascotState(LOTTIE_URLS.mascot_happy);
        };
        source.start(nextStartTimeRef.current);
        nextStartTimeRef.current += buffer.duration;
        sourcesRef.current.add(source);
      },
      onInterrupted: () => {
        sourcesRef.current.forEach(s => s.stop());
        sourcesRef.current.clear();
        nextStartTimeRef.current = 0;
      },
      onClose: () => {
        setCurrentStep('selection');
      }
    });

    sessionRef.current = await sessionPromise;
  };

  const fetchNewExercise = async (type: ExerciseType) => {
    setCurrentStep('generating');
    setMascotState(LOTTIE_URLS.mascot_encourage);

    const childTopics = ["animales de la selva", "el espacio sideral", "frutas de colores", "juguetes", "peces", "perritos", "arcoiris", "dinosaurios"];
    const randomTopic = childTopics[Math.floor(Math.random() * childTopics.length)];
    const config = { duration: 5, repetitions: 3, reward: RewardTrigger.STARS };

    try {
      const result = await generateStreamingExercise(type, Level.BASIC, randomTopic, config, () => {});
      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0].trim());

        // ¡NUEVO! Generar la imagen con IA para que coordine perfectamente
        const aiImageUrl = await generateExerciseImage(parsed.image_keyword || parsed.target);
        parsed.imageUrl = aiImageUrl;

        setTimeout(() => {
          setGeneratedExercise(parsed);
          setCurrentStep('playing');
          setMascotState(LOTTIE_URLS.mascot_happy);
          setSessionHistory(prev => [...prev, parsed.target]);
          speak(parsed.content);
        }, 1200);
      }
    } catch (e) {
      console.error("Fetch error:", e);
      setCurrentStep('selection');
    }
  };

  const handleModuleSelect = (type: ExerciseType) => {
    setDirection(1);
    setSelectedModule(type);
    fetchNewExercise(type);
  };

  const handleListen = useCallback(() => {
    if (isListening || !generatedExercise) return;
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedbackMsg('¡Te escucho! 👂');

    startRecognition(
      (result) => {
        setIsListening(false);
        const score = compareText(result, generatedExercise.target || '');
        if (score > 0.6) {
          handleSuccess();
        } else {
          setMascotState(LOTTIE_URLS.mascot_happy);
          setFeedbackMsg('¡Casi! Otra vez');
          speak("¿Lo intentamos de nuevo?");
        }
      },
      () => {
        setIsListening(false);
        setFeedbackMsg('¡Inténtalo otra vez!');
      }
    );
  }, [generatedExercise, isListening]);

  const handleSuccess = () => {
    setMascotState(LOTTIE_URLS.mascot_celebrate);
    setFeedbackMsg('¡EXCELENTE! ⭐');
    setShowStars(true);
    speak("¡Lo hiciste genial! ¡Eres una super estrella!");
    setTimeout(() => {
      setShowStars(false);
      setDirection(1);
      setCurrentStep('feedback');
    }, 2500);
  };

  const handleFeedbackResponse = (status: 'ok' | 'process' | 'repeat') => {
    setDirection(1);
    if (status === 'repeat') {
      setCurrentStep('playing');
      setMascotState(LOTTIE_URLS.mascot_happy);
      setFeedbackMsg('');
      speak(generatedExercise.content);
    } else if (sessionHistory.length < 3) {
      if (selectedModule) fetchNewExercise(selectedModule);
    } else {
      setShowConfetti(true);
      setCurrentStep('reward');
    }
  };

  return (
    <Layout role="child">
      <div className="h-full flex flex-col items-center justify-center relative overflow-hidden perspective-1000">

        {showConfetti && (
          <div className="absolute inset-0 z-[100] pointer-events-none">
            <LottiePlayer url={LOTTIE_URLS.confetti} className="w-full h-full" />
          </div>
        )}

        <AnimatePresence mode="wait" custom={direction}>
          {/* BIENVENIDA */}
          {currentStep === 'welcome' && (
            <motion.div 
              key="welcome" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="bg-white/95 backdrop-blur-xl p-10 rounded-[4rem] border-[12px] border-white shadow-2xl flex flex-col items-center max-w-lg w-full text-center"
            >
              <div className="w-64 h-64 mb-6">
                <LottiePlayer url={LOTTIE_URLS.mascot_happy} className="w-full h-full" />
              </div>
              <h2 className="text-4xl font-black text-blue-900 mb-8 uppercase">¡HOLA CAMPEÓN!</h2>
              <div className="flex flex-col gap-5 w-full">
                <motion.button 
                  whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                  onClick={() => { setDirection(1); setCurrentStep('selection'); }}
                  className="bg-yellow-400 text-blue-900 text-3xl font-black py-6 rounded-[2rem] shadow-[0_10px_0_#ca8a04] border-4 border-white transition-all"
                >
                  ¡EMPEZAR! 🚀
                </motion.button>
                <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => navigate(`/child/1/collection`)} className="bg-blue-500 text-white font-black py-4 rounded-2xl border-4 border-white shadow-lg text-lg">MIS PREMIOS 🎁</button>
                  <button onClick={() => navigate('/')} className="bg-red-500 text-white font-black py-4 rounded-2xl border-4 border-white shadow-lg text-lg">SALIR 🏠</button>
                </div>
              </div>
            </motion.div>
          )}

          {/* SELECCIÓN DE MÓDULO */}
          {currentStep === 'selection' && (
            <motion.div 
              key="selection" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="w-full max-w-5xl px-4"
            >
              <h2 className="text-4xl font-black text-blue-900 text-center mb-10 uppercase tracking-widest drop-shadow-lg">¿Qué quieres hacer hoy?</h2>
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6">
                {[
                  { type: ExerciseType.ARTICULATION, icon: '👄', color: 'bg-orange-400' },
                  { type: ExerciseType.VOCABULARY, icon: '🍎', color: 'bg-green-500' },
                  { type: ExerciseType.COMPREHENSION, icon: '🧠', color: 'bg-purple-500' },
                  { type: ExerciseType.SENTENCES, icon: '📝', color: 'bg-blue-500' }
                ].map((mod) => (
                  <motion.button
                    key={mod.type} whileHover={{ scale: 1.08 }} whileTap={{ scale: 0.9 }}
                    onClick={() => handleModuleSelect(mod.type)}
                    className={`${mod.color} border-8 border-white/50 aspect-square rounded-[3rem] shadow-2xl flex flex-col items-center justify-center p-6 text-white group`}
                  >
                    <span className="text-6xl mb-4 group-hover:animate-bounce">{mod.icon}</span>
                    <span className="font-black text-lg uppercase tracking-tighter leading-tight">{mod.type}</span>
                  </motion.button>
                ))}

                <motion.button
                  whileHover={{ scale: 1.1, rotate: 2 }} whileTap={{ scale: 0.9 }}
                  onClick={startLiveChat}
                  className="bg-gradient-to-br from-pink-500 to-rose-600 border-8 border-white/50 aspect-square rounded-[3rem] shadow-2xl flex flex-col items-center justify-center p-6 text-white group"
                >
                  <span className="text-7xl mb-4 animate-pulse">💬</span>
                  <span className="font-black text-xl uppercase tracking-tighter leading-tight">HABLAR CON AMIGO</span>
                </motion.button>
              </div>
            </motion.div>
          )}

          {/* MODO LIVE CHAT */}
          {currentStep === 'live_chat' && (
            <motion.div 
              key="live_chat" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="flex flex-col items-center gap-10 max-w-4xl w-full"
            >
               <div className="bg-white/80 backdrop-blur-md p-10 rounded-[5rem] border-[15px] border-pink-100 shadow-2xl text-center w-full relative">
                  <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-rose-500 text-white px-8 py-3 rounded-full font-black shadow-lg animate-pulse uppercase tracking-widest border-4 border-white">
                    ¡Charlando en vivo! 🎙️
                  </div>

                  <div className="flex flex-col items-center gap-6">
                    <div className="relative w-80 h-80">
                       <LottiePlayer url={mascotState} className="w-full h-full" />
                       <div className="absolute bottom-0 left-0 w-full flex justify-center gap-1">
                          {[1,2,3,4,5].map(i => (
                            <motion.div 
                              key={i} animate={{ height: [10, 40, 10] }} 
                              transition={{ repeat: Infinity, duration: 0.5, delay: i * 0.1 }}
                              className="w-2 bg-rose-400 rounded-full"
                            />
                          ))}
                       </div>
                    </div>
                    <p className="text-3xl font-black text-blue-900 mt-4 italic">"Háblame, ¡te estoy escuchando!"</p>
                  </div>
               </div>

               <button 
                onClick={() => { stopLiveSession(); setCurrentStep('selection'); }}
                className="bg-white text-rose-600 font-black px-12 py-6 rounded-full border-4 border-rose-100 shadow-xl text-2xl hover:bg-rose-500 hover:text-white transition-all"
               >
                 TERMINAR CHARLA 🏠
               </button>
            </motion.div>
          )}

          {/* GENERANDO CON IA */}
          {currentStep === 'generating' && (
            <motion.div 
              key="generating" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="flex flex-col items-center text-center"
            >
              <div className="relative w-80 h-80 mb-8">
                 <LottiePlayer url={LOTTIE_URLS.clouds} className="w-full h-full" />
              </div>
              <h2 className="text-5xl font-black text-blue-900 animate-pulse uppercase">¡Dibujando tu juego! ✨</h2>
              <p className="text-2xl font-bold text-blue-500 mt-4 italic">La IA está creando una ilustración para ti...</p>
            </motion.div>
          )}

          {/* JUGANDO */}
          {currentStep === 'playing' && generatedExercise && (
            <motion.div 
              key="playing" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="grid lg:grid-cols-2 gap-10 w-full max-w-6xl items-center px-4"
            >
              <div className="bg-white p-6 md:p-10 rounded-[4rem] border-[12px] border-blue-50 shadow-2xl flex flex-col text-center">
                 <div className="aspect-video rounded-[2.5rem] overflow-hidden border-4 border-slate-50 mb-6 shadow-inner relative bg-blue-50">
                    <img 
                      src={generatedExercise.imageUrl} 
                      className="w-full h-full object-contain p-4" 
                      alt="Ilustración IA" 
                    />
                 </div>
                 <h3 className="text-3xl md:text-4xl font-black text-blue-900 mb-6">{generatedExercise.content}</h3>
                 {selectedModule === ExerciseType.COMPREHENSION && (
                   <div className="grid grid-cols-2 gap-4">
                     {["pájaro", "pez", "perro", "gato"].map(opt => (
                       <button 
                        key={opt} onClick={() => opt.toLowerCase() === generatedExercise.target.toLowerCase() ? handleSuccess() : speak("¡Casi! Intenta de nuevo")}
                        className="bg-blue-50 border-4 border-blue-100 p-4 rounded-2xl font-black text-blue-700 text-2xl hover:bg-blue-500 hover:text-white transition-all shadow-md active:scale-95"
                       >
                         {opt}
                       </button>
                     ))}
                   </div>
                 )}
              </div>

              <div className="flex flex-col items-center gap-8 relative">
                {showStars && (
                  <div className="absolute inset-0 z-50 pointer-events-none">
                    <LottiePlayer url={LOTTIE_URLS.stars} className="w-full h-full" />
                  </div>
                )}
                <div className={`relative transition-all duration-700 ${isIdle ? 'scale-110' : ''}`}>
                  <LottiePlayer url={mascotState} className="h-80 w-80" />
                </div>
                <div className="flex flex-col items-center gap-4 w-full">
                  {feedbackMsg && <div className="bg-yellow-400 px-8 py-3 rounded-full font-black text-blue-900 text-2xl border-4 border-white shadow-lg animate-bounce">{feedbackMsg}</div>}
                  <div className="flex gap-6">
                    <button onClick={() => speak(generatedExercise.content)} className="bg-blue-600 w-24 h-24 rounded-3xl text-4xl shadow-xl border-4 border-blue-300 text-white">🔊</button>
                    <button 
                      onClick={handleListen} disabled={isListening}
                      className={`w-36 h-36 rounded-full text-7xl flex items-center justify-center text-white border-[10px] shadow-2xl transition-all ${isListening ? 'bg-red-500 border-red-200 animate-pulse' : 'bg-green-500 border-green-200'}`}
                    >
                      {isListening ? '🛑' : '🎤'}
                    </button>
                  </div>
                </div>
              </div>
            </motion.div>
          )}

          {/* Pantalla de Feedback */}
          {currentStep === 'feedback' && (
            <motion.div 
              key="feedback" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="bg-white p-12 rounded-[5rem] border-[15px] border-yellow-200 shadow-2xl text-center max-w-xl w-full"
            >
              <h2 className="text-4xl font-black text-blue-900 mb-4 uppercase">¿Cómo te fue?</h2>
              <div className="grid grid-cols-3 gap-6 mt-10">
                {[
                  { label: 'Repetir', icon: '🔄', color: 'bg-red-100 text-red-600', val: 'repeat' },
                  { label: 'En proceso', icon: '⏳', color: 'bg-blue-100 text-blue-600', val: 'process' },
                  { label: '¡Lo logré!', icon: '✅', color: 'bg-green-100 text-green-600', val: 'ok' }
                ].map(btn => (
                  <motion.button
                    key={btn.val} whileHover={{ scale: 1.15, rotate: 2 }} whileTap={{ scale: 0.9 }}
                    onClick={() => handleFeedbackResponse(btn.val as any)}
                    className={`${btn.color} p-6 rounded-[2.5rem] flex flex-col items-center gap-3 border-4 border-white shadow-lg transition-colors`}
                  >
                    <span className="text-6xl">{btn.icon}</span>
                    <span className="font-black text-sm uppercase tracking-tighter">{btn.label}</span>
                  </motion.button>
                ))}
              </div>
            </motion.div>
          )}

          {/* Recompensa */}
          {currentStep === 'reward' && (
            <motion.div 
              key="reward" custom={direction} variants={screenVariants} initial="initial" animate="animate" exit="exit"
              className="bg-white p-16 rounded-[6rem] text-center shadow-2xl border-[20px] border-yellow-300 max-w-2xl w-full"
            >
              <motion.div initial={{ scale: 0 }} animate={{ scale: 1, rotate: [0, 15, -15, 0] }} transition={{ type: "spring", delay: 0.4 }} className="text-[12rem] mb-8">🏆</motion.div>
              <h2 className="text-7xl font-black text-blue-950 mb-4 uppercase leading-none">¡LO LOGRASTE!</h2>
              <button 
                onClick={() => navigate(`/child/1/collection`)}
                className="w-full bg-green-500 text-white font-black py-10 rounded-[3.5rem] text-4xl shadow-[0_15px_0_#166534] border-4 border-white transition-all"
              >
                VER MI PREMIO 🎁
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </Layout>
  );
};

export default ChildPlay;

import React, { useState } from 'react';
import Layout from '../components/Layout';
import { generateStreamingExercise, generateExerciseImage } from '../services/geminiService';
import { ExerciseType, Level, RewardTrigger } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const AIGenerator: React.FC = () => {
  const [type, setType] = useState<ExerciseType>(ExerciseType.ARTICULATION);
  const [level, setLevel] = useState<Level>(Level.BASIC);
  const [topic, setTopic] = useState('');

  const [duration, setDuration] = useState(5);
  const [repetitions, setRepetitions] = useState(3);
  const [reward, setReward] = useState<RewardTrigger>(RewardTrigger.CONFETTI);

  const [isGenerating, setIsGenerating] = useState(false);
  const [isApproved, setIsApproved] = useState(false);
  const [streamedContent, setStreamedContent] = useState('');
  const [generatedExercise, setGeneratedExercise] = useState<any>(null);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setIsApproved(false);
    setStreamedContent('');
    setGeneratedExercise(null);

    try {
      const config = { duration, repetitions, reward };
      const result = await generateStreamingExercise(type, level, topic, config, (chunk) => {
        setStreamedContent(chunk);
      });

      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0].trim());

        // Generar la imagen coordinada con IA
        const aiImageUrl = await generateExerciseImage(parsed.image_keyword || parsed.target);
        parsed.imageUrl = aiImageUrl;

        parsed.config = config;
        setGeneratedExercise(parsed);
      }
    } catch (e) {
      console.error("Generación fallida:", e);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleApprove = () => {
    setIsApproved(true);
  };

  const goToDashboard = () => {
    window.location.hash = '#/dashboard';
  };

  return (
    <Layout>
      <div className="max-w-7xl mx-auto px-4 pb-20">
        <header className="mb-10 flex justify-between items-center">
          <div>
            <h2 className="text-4xl font-black text-blue-950">Fábrica de Ideas ✨</h2>
            <p className="text-gray-500 font-bold">Configura y genera experiencias de aprendizaje únicas con imágenes sincronizadas.</p>
          </div>
          <button 
            onClick={goToDashboard} 
            className="bg-white border-4 border-gray-100 px-6 py-3 rounded-2xl font-black text-gray-500 hover:text-blue-500 transition-colors shadow-sm"
          >
            Volver
          </button>
        </header>

        <div className="grid lg:grid-cols-[1fr_1.2fr] gap-8 items-start">
          <div className="space-y-6">
            <div className="bg-white p-8 rounded-[3rem] shadow-xl border-4 border-gray-50">
              <h3 className="text-xl font-black mb-6 text-blue-900 flex items-center gap-2">
                <span className="p-2 bg-blue-100 rounded-xl text-blue-600">⚙️</span>
                Configuración del Ejercicio
              </h3>

              <div className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">Módulo</label>
                    <select 
                      className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 font-bold text-sm focus:border-blue-400 outline-none transition-all" 
                      value={type} 
                      onChange={e => setType(e.target.value as ExerciseType)}
                    >
                      {Object.values(ExerciseType).map(v => <option key={v} value={v}>{v}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">Nivel</label>
                    <select 
                      className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 font-bold text-sm focus:border-blue-400 outline-none transition-all" 
                      value={level} 
                      onChange={e => setLevel(e.target.value as Level)}
                    >
                      {Object.values(Level).map(v => <option key={v} value={v}>{v}</option>)}
                    </select>
                  </div>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">Interés del Niño (Topic)</label>
                  <input 
                    type="text" 
                    className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 font-bold text-sm focus:border-blue-400 outline-none" 
                    placeholder="Ej: Dinosaurios, espacio, gatitos..." 
                    value={topic} 
                    onChange={e => setTopic(e.target.value)} 
                  />
                </div>

                <hr className="border-gray-100" />

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">Duración (min)</label>
                    <div className="flex items-center gap-2">
                       <input 
                        type="range" min="1" max="15" step="1"
                        className="flex-grow accent-blue-600 h-2 bg-gray-100 rounded-lg appearance-none cursor-pointer"
                        value={duration}
                        onChange={e => setDuration(parseInt(e.target.value))}
