                    </div>
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">Repeticiones</label>
                    <div className="flex items-center gap-2">
                       <input 
                        type="range" min="1" max="10" step="1"
                        className="flex-grow accent-orange-500 h-2 bg-gray-100 rounded-lg appearance-none cursor-pointer"
                        value={repetitions}
                        onChange={e => setRepetitions(parseInt(e.target.value))}
                       />
