                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">Disparador de Recompensa</label>
                  <div className="grid grid-cols-2 gap-2">
                    {Object.values(RewardTrigger).map(rt => (
                      <button
                        key={rt}
