                      >
                        {rt === RewardTrigger.CONFETTI && '🎉 '}
                        {rt === RewardTrigger.STARS && '⭐ '}
                        {rt === RewardTrigger.SOUND && '🔔 '}
                        {rt === RewardTrigger.MASCOT && '🐶 '}
                        {rt}
                      </button>
                    ))}
                  </div>
                </div>

                <motion.button 
                  whileHover={{ scale: 1.02 }} 
                  whileTap={{ scale: 0.98 }}
                  onClick={handleGenerate} 
                  disabled={isGenerating || !topic} 
                  className="w-full py-5 rounded-[2rem] font-black text-white bg-gradient-to-r from-blue-600 to-indigo-700 shadow-xl disabled:opacity-50 transition-all border-b-8 border-indigo-900 overflow-hidden relative group"
                >
                  <span className="relative z-10">{isGenerating ? "DIBUJANDO IDEAS..." : "✨ GENERAR JUEGO CON IA"}</span>
                  <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700" />
                </motion.button>
              </div>
            </div>
          </div>

          <div className="bg-white p-8 md:p-10 rounded-[3rem] shadow-xl border-4 border-gray-50 min-h-[600px] flex flex-col relative overflow-hidden">
            <div className="flex justify-between items-center mb-6">
