                  <button onClick={goToDashboard} className="w-full bg-green-600 text-white font-black py-6 rounded-3xl shadow-[0_10px_0_#166534] border-4 border-white text-2xl transition-all">PANEL DE CONTROL 📋</button>
                </motion.div>
              ) : generatedExercise ? (
                <motion.div key="preview" initial={{ y: 30, opacity: 0 }} animate={{ y: 0, opacity: 1 }} className="bg-blue-50/30 p-8 rounded-[3rem] border-4 border-blue-50 flex-grow flex flex-col">
                  <div className="grid grid-cols-1 md:grid-cols-[1.2fr_1.5fr] gap-8 flex-grow">
                    <div className="w-full h-full min-h-[200px] bg-white rounded-[2rem] overflow-hidden shadow-xl border-4 border-white flex items-center justify-center">
                      <img src={generatedExercise.imageUrl} className="w-full h-full object-contain p-2" alt="Ilustración generada" />
                    </div>
                    <div className="flex flex-col justify-center">
                      <div className="bg-white p-6 rounded-2xl shadow-sm border border-blue-100 mb-4">
                        <p className="font-black text-blue-950 text-2xl leading-tight mb-2">"{generatedExercise.content}"</p>
                        <p className="text-blue-500 font-bold">Objetivo: <span className="underline decoration-yellow-400 decoration-4">{generatedExercise.target}</span></p>
                      </div>
                      <div className="p-4 bg-purple-50 rounded-2xl border border-purple-100 italic text-purple-700 text-xs">
                        <strong>💡 Pedagogía:</strong> {generatedExercise.pedagogical_note}
                      </div>
                    </div>
                  </div>
                  <div className="mt-8 flex gap-4">
                    <button onClick={handleApprove} className="flex-1 bg-green-500 text-white font-black py-5 rounded-[2rem] shadow-[0_8px_0_#166534] border-4 border-white text-xl">Aprobar ✅</button>
                    <button onClick={() => setGeneratedExercise(null)} className="flex-1 bg-white text-gray-400 font-black py-5 rounded-[2rem] border-4 border-gray-100 text-xl">Descartar</button>
                  </div>
                </motion.div>
              ) : !isGenerating && (
                <div className="flex-grow flex flex-col items-center justify-center text-gray-300 italic font-bold">
                  <div className="text-9xl mb-8 opacity-20">🪄</div>
                  <p className="text-xl max-w-xs text-center">Configura el tema para ver la ilustración personalizada de la IA...</p>
                </div>
              )}
            </AnimatePresence>

            {isGenerating && (
              <div className="flex-grow flex flex-col items-center justify-center gap-6">
                <div className="relative">
                  <div className="w-24 h-24 border-[10px] border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center font-black text-blue-600 animate-pulse text-xs">IA ART</div>
                </div>
                <p className="font-black text-blue-400 animate-pulse tracking-widest text-sm uppercase">Ilustrando el ejercicio...</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
