                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest">Edad</label>
                      <input 
                        type="number" value={formData.age} onChange={e => setFormData({...formData, age: parseInt(e.target.value)})}
