import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Layout from '../components/Layout';
import { motion, AnimatePresence } from 'framer-motion';
import LottiePlayer from '../components/LottiePlayer';
import { LOTTIE_URLS } from '../constants';
import { speak, startRecognition, compareText } from '../services/speechService';
import { generateStreamingExercise, generateExerciseImage } from '../services/geminiService';
import { connectLiveChat, encodePCM, decodePCM, decodeAudioData } from '../services/liveApiService';
import { ExerciseType, Level, RewardTrigger, Child } from '../types';

type PlayStep = 'welcome' | 'selection' | 'generating' | 'playing' | 'live_chat' | 'feedback' | 'reward';

const screenVariants = {
  initial: (direction: number) => ({
    opacity: 0,
    x: direction > 0 ? 500 : -500,
    scale: 0.95
  }),
  animate: {
    opacity: 1,
    x: 0,
    scale: 1,
    transition: { type: "spring", stiffness: 100, damping: 20 }
  },
  exit: (direction: number) => ({
    opacity: 0,
    x: direction < 0 ? 500 : -500,
    scale: 0.95,
    transition: { duration: 0.3 }
  })
};

const ChildPlay: React.FC = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const [currentChild, setCurrentChild] = useState<Child | null>(null);
  const [currentStep, setCurrentStep] = useState<PlayStep>('welcome');
  const [selectedModule, setSelectedModule] = useState<ExerciseType | null>(null);
  const [direction, setDirection] = useState(1);
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [isListening, setIsListening] = useState(false);
  const [feedbackMsg, setFeedbackMsg] = useState('');
  const [showConfetti, setShowConfetti] = useState(false);
  const [showStars, setShowStars] = useState(false);
  const [generatedExercise, setGeneratedExercise] = useState<any>(null);

  const audioContextOutRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem('hja_children') || '[]');
    const child = saved.find((c: any) => c.id === id);
    if (child) {
      setCurrentChild(child);
    } else {
      navigate('/dashboard');
    }
  }, [id, navigate]);

  useEffect(() => {
    if (currentStep === 'welcome' && currentChild) {
      const hour = new Date().getHours();
      let greeting = `¡Hola ${currentChild.name}!`;
      if (hour < 12) greeting = `¡Buenos días ${currentChild.name}!`;
      else if (hour < 20) greeting = `¡Buenas tardes ${currentChild.name}!`;

      speak(`${greeting} ¿Qué quieres jugar hoy?`);
    }
  }, [currentStep, currentChild]);

  const fetchNewExercise = async (type: ExerciseType) => {
    if (!currentChild) return;
    setCurrentStep('generating');
    setMascotState(LOTTIE_URLS.mascot_encourage);

    try {
      const result = await generateStreamingExercise(
        type, 
        currentChild, 
        { duration: 5, repetitions: 3, reward: RewardTrigger.STARS }, 
        () => {}
      );

      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0].trim());
        const aiImageUrl = await generateExerciseImage(parsed.image_keyword || parsed.target, currentChild.age);
        parsed.imageUrl = aiImageUrl;

        setGeneratedExercise(parsed);
        setCurrentStep('playing');
        setMascotState(LOTTIE_URLS.mascot_happy);
        speak(parsed.content);
      }
    } catch (e) {
      setCurrentStep('selection');
    }
  };

  const handleModuleSelect = (type: ExerciseType) => {
    setDirection(1);
    setSelectedModule(type);
    fetchNewExercise(type);
  };

  const handleListen = useCallback(() => {
    if (isListening || !generatedExercise) return;
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedbackMsg('¡Te escucho! 👂');

    startRecognition(
      (result) => {
        setIsListening(false);
        const score = compareText(result, generatedExercise.target || '');
        if (score > 0.6) {
          handleSuccess();
        } else {
          setMascotState(LOTTIE_URLS.mascot_happy);
          setFeedbackMsg('¡Casi! Otra vez');
          speak("¿Lo intentamos de nuevo?");
        }
      },
      () => {
        setIsListening(false);
        setFeedbackMsg('¡Inténtalo otra vez!');
      }
    );
  }, [generatedExercise, isListening]);

  const handleSuccess = () => {
    setMascotState(LOTTIE_URLS.mascot_celebrate);
    setFeedbackMsg('¡MUY BIEN! ⭐');
    setShowStars(true);
    speak("¡Lo hiciste genial!");

    const saved = JSON.parse(localStorage.getItem('hja_children') || '[]');
    const updated = saved.map((c: any) => c.id === id ? { ...c, stars: c.stars + 1, lastSession: new Date().toLocaleDateString() } : c);
    localStorage.setItem('hja_children', JSON.stringify(updated));

    setTimeout(() => {
      setShowStars(false);
      setCurrentStep('feedback');
    }, 2500);
  };

  return (
    <Layout role="child">
      <div className="h-full flex flex-col items-center justify-center relative overflow-hidden">
        {showConfetti && <div className="absolute inset-0 z-[100]"><LottiePlayer url={LOTTIE_URLS.confetti} /></div>}

        <AnimatePresence mode="wait" custom={direction}>
          {currentStep === 'welcome' && (
            <motion.div key="welcome" variants={screenVariants} initial="initial" animate="animate" exit="exit" className="text-center bg-white/90 p-10 rounded-[4rem] shadow-2xl border-[12px] border-white max-w-lg">
              <div className="w-64 h-64 mx-auto mb-6"><LottiePlayer url={LOTTIE_URLS.mascot_happy} /></div>
              <h2 className="text-4xl font-black text-blue-900 mb-8 uppercase tracking-tighter">¡HOLA {currentChild?.name.split(' ')[0]}!</h2>
              <button 
                onClick={() => { setDirection(1); setCurrentStep('selection'); }}
                className="w-full bg-yellow-400 text-blue-900 text-3xl font-black py-6 rounded-[2.5rem] shadow-[0_10px_0_#ca8a04] border-4 border-white active:translate-y-2 transition-all"
              >
                ¡JUGAR! 🚀
              </button>
            </motion.div>
          )}

          {currentStep === 'selection' && (
            <motion.div key="selection" variants={screenVariants} initial="initial" animate="animate" exit="exit" className="w-full max-w-5xl px-4">
              <h2 className="text-4xl font-black text-blue-900 text-center mb-10 uppercase tracking-widest drop-shadow-lg">¿Qué quieres hacer?</h2>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {[
                  { type: ExerciseType.ARTICULATION, icon: '👄', color: 'bg-orange-400' },
                  { type: ExerciseType.VOCABULARY, icon: '🍎', color: 'bg-green-500' },
                  { type: ExerciseType.COMPREHENSION, icon: '🧠', color: 'bg-purple-500' },
                  { type: ExerciseType.SENTENCES, icon: '📝', color: 'bg-blue-500' }
                ].map((mod) => (
                  <motion.button
                    key={mod.type} whileHover={{ scale: 1.08 }} whileTap={{ scale: 0.9 }}
                    onClick={() => handleModuleSelect(mod.type)}
                    className={`${mod.color} border-8 border-white aspect-square rounded-[3rem] shadow-2xl flex flex-col items-center justify-center text-white`}
                  >
                    <span className="text-7xl mb-4">{mod.icon}</span>
                    <span className="font-black text-xl uppercase">{mod.type}</span>
                  </motion.button>
                ))}
              </div>
            </motion.div>
          )}

          {currentStep === 'generating' && (
            <motion.div key="generating" variants={screenVariants} initial="initial" animate="animate" exit="exit" className="text-center">
              <div className="w-80 h-80 mx-auto mb-8"><LottiePlayer url={LOTTIE_URLS.clouds} /></div>
              <h2 className="text-5xl font-black text-blue-900 animate-pulse uppercase">¡Dibujando tu juego! ✨</h2>
            </motion.div>
          )}

          {currentStep === 'playing' && generatedExercise && (
            <motion.div key="playing" variants={screenVariants} initial="initial" animate="animate" exit="exit" className="grid lg:grid-cols-2 gap-10 w-full max-w-6xl items-center px-4">
              <div className="bg-white p-10 rounded-[4rem] border-[12px] border-blue-50 shadow-2xl text-center">
                 <div className="aspect-square rounded-[3rem] overflow-hidden border-4 border-slate-50 mb-6 bg-blue-50">
                    <img src={generatedExercise.imageUrl} className="w-full h-full object-contain p-6" alt="Juego" />
                 </div>
                 <h3 className="text-4xl font-black text-blue-900">{generatedExercise.content}</h3>
              </div>
              <div className="flex flex-col items-center gap-8">
                <div className="w-80 h-80"><LottiePlayer url={mascotState} /></div>
                <div className="flex flex-col items-center gap-4">
                  {feedbackMsg && <div className="bg-yellow-400 px-8 py-3 rounded-full font-black text-blue-900 text-2xl border-4 border-white shadow-lg animate-bounce">{feedbackMsg}</div>}
                  <div className="flex gap-6">
                    <button onClick={() => speak(generatedExercise.content)} className="bg-blue-600 w-24 h-24 rounded-3xl text-4xl border-4 border-blue-300 text-white">🔊</button>
                    <button 
                      onClick={handleListen}
                      className={`w-36 h-36 rounded-full text-7xl flex items-center justify-center text-white border-[10px] shadow-2xl transition-all ${isListening ? 'bg-red-500 border-red-200 animate-pulse' : 'bg-green-500 border-green-200'}`}
                    >
                      {isListening ? '🛑' : '🎤'}
                    </button>
                  </div>
                </div>
              </div>
            </motion.div>
          )}

          {currentStep === 'feedback' && (
            <motion.div key="feedback" variants={screenVariants} initial="initial" animate="animate" exit="exit" className="bg-white p-12 rounded-[5rem] border-[15px] border-yellow-200 text-center max-w-xl">
              <h2 className="text-4xl font-black text-blue-900 mb-10">¿CÓMO LO HICIMOS?</h2>
              <div className="grid grid-cols-3 gap-4">
                {['repeat', 'process', 'ok'].map((val) => (
                  <button key={val} onClick={() => navigate('/dashboard')} className="p-6 rounded-3xl border-4 border-slate-50 shadow-lg text-4xl">
                    {val === 'ok' ? '✅' : val === 'repeat' ? '🔄' : '⏳'}
                  </button>
                ))}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </Layout>
  );
};

