            <div className="bg-gray-900 rounded-[2rem] p-4 font-mono text-green-400 text-[10px] mb-8 overflow-hidden h-28 border-4 border-gray-800 relative shadow-inner">
              <div className="absolute top-2 right-4 text-[8px] text-gray-500 uppercase font-black">GenAI Log</div>
              <div className="break-all whitespace-pre-wrap">
                {streamedContent || "// Esperando configuración..."}
