                  <div className="text-9xl mb-6">🚀</div>
                  <h4 className="text-4xl font-black text-green-800 mb-2">¡Sincronizado!</h4>
                  <p className="text-green-600 font-bold mb-10 max-w-sm">El ejercicio con imagen personalizada está listo para Mateo.</p>
                  <button onClick={goToDashboard} className="w-full bg-green-600 text-white font-black py-6 rounded-3xl shadow-[0_10px_0_#166534] border-4 border-white text-2xl transition-all">PANEL DE CONTROL 📋</button>
