                        <p className="font-black text-blue-950 text-2xl leading-tight mb-2">"{generatedExercise.content}"</p>
                        <p className="text-blue-500 font-bold">Objetivo: <span className="underline decoration-yellow-400 decoration-4">{generatedExercise.target}</span></p>
                      </div>
                      <div className="p-4 bg-purple-50 rounded-2xl border border-purple-100 italic text-purple-700 text-xs">
                        <strong>💡 Pedagogía:</strong> {generatedExercise.pedagogical_note}
