                  <div className="mt-8 flex gap-4">
                    <button onClick={handleApprove} className="flex-1 bg-green-500 text-white font-black py-5 rounded-[2rem] shadow-[0_8px_0_#166534] border-4 border-white text-xl">Aprobar ✅</button>
