              </div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default AIGenerator;

import React, { useState, useEffect } from 'react';
import Layout from '../components/Layout';
import { motion, AnimatePresence } from 'framer-motion';
import { Child, Level } from '../types';

const Dashboard: React.FC = () => {
  const [children, setChildren] = useState<Child[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingChild, setEditingChild] = useState<Child | null>(null);
  const [viewingDetails, setViewingDetails] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    age: 5,
    characteristics: '',
    level: Level.BASIC
  });

  useEffect(() => {
    const saved = localStorage.getItem('hja_children');
    if (saved) {
      setChildren(JSON.parse(saved));
    } else {
      const initial = [
        { id: '1', name: 'Mateo R.', age: 5, characteristics: 'Dificultad con fonema /r/, le gusta el espacio.', objectives: [], level: Level.BASIC, stars: 45, collection: [], lastSession: '25/10/24' },
      ];
      setChildren(initial);
      localStorage.setItem('hja_children', JSON.stringify(initial));
    }
  }, []);

  const saveToLocal = (newChildren: Child[]) => {
    setChildren(newChildren);
    localStorage.setItem('hja_children', JSON.stringify(newChildren));
  };

  const handleOpenModal = (child?: Child) => {
    if (child) {
      setEditingChild(child);
      setFormData({ name: child.name, age: child.age, characteristics: child.characteristics, level: child.level });
    } else {
      setEditingChild(null);
      setFormData({ name: '', age: 5, characteristics: '', level: Level.BASIC });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingChild) {
      const updated = children.map(c => c.id === editingChild.id ? { ...c, ...formData } : c);
      saveToLocal(updated);
    } else {
      const newChild: Child = {
        id: Date.now().toString(),
        ...formData,
        objectives: [],
        stars: 0,
        collection: [],
        lastSession: new Date().toLocaleDateString()
      };
      saveToLocal([...children, newChild]);
    }
    setIsModalOpen(false);
  };

  return (
    <Layout>
      <div className="max-w-6xl mx-auto px-4 h-full flex flex-col">
        <header className="py-8 flex justify-between items-center">
          <div>
            <h2 className="text-3xl font-extrabold text-slate-800">Mis Alumnos</h2>
            <p className="text-slate-400 font-medium">Gestiona y personaliza cada sesión de forma sencilla.</p>
          </div>
          <button 
            onClick={() => handleOpenModal()}
            className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all active:scale-95"
          >
            + Añadir Niño
          </button>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-10">
          {children.map((child) => (
            <motion.div
              layout
              key={child.id}
              className="bg-white border border-slate-100 rounded-[2.5rem] p-6 shadow-sm hover:shadow-md transition-shadow flex flex-col group relative overflow-hidden"
            >
              <div className="flex items-center gap-4 mb-6">
                <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-xl font-bold text-blue-600 border border-slate-100">
                  {child.name[0]}
                </div>
                <div className="flex-1">
                  <h3 className="text-xl font-bold text-slate-800">{child.name}</h3>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[10px] font-bold px-2 py-0.5 bg-blue-50 text-blue-600 rounded-md uppercase tracking-wider">{child.age} años</span>
                    <span className="text-[10px] font-bold px-2 py-0.5 bg-slate-50 text-slate-500 rounded-md uppercase tracking-wider">{child.level}</span>
                  </div>
                </div>
              </div>

              <div className="space-y-3 mb-6 flex-grow">
                 <button 
                   onClick={() => setViewingDetails(viewingDetails === child.id ? null : child.id)}
                   className="text-[11px] font-bold text-blue-500 hover:text-blue-700 flex items-center gap-1 transition-colors"
                 >
                   {viewingDetails === child.id ? '🔼 Ocultar detalles' : '🔽 Ver necesidades terapéuticas'}
                 </button>

                 <AnimatePresence>
                   {viewingDetails === child.id && (
                     <motion.p 
                       initial={{ height: 0, opacity: 0 }} 
                       animate={{ height: 'auto', opacity: 1 }} 
                       exit={{ height: 0, opacity: 0 }}
                       className="text-xs text-slate-500 leading-relaxed overflow-hidden italic"
                     >
                       "{child.characteristics}"
                     </motion.p>
                   )}
                 </AnimatePresence>
              </div>

              <div className="flex items-center justify-between pt-4 border-t border-slate-50">
                 <div className="flex items-center gap-1 text-yellow-500 font-bold text-sm">
                   ⭐ {child.stars}
                 </div>
                 <div className="flex gap-2">
                    <button 
                      onClick={() => window.location.hash = `#/child/${child.id}/play`}
                      className="bg-green-500 text-white px-5 py-2.5 rounded-xl font-bold text-sm shadow-sm hover:bg-green-600 transition-colors"
                    >
                      Jugar
                    </button>
                    <button 
                      onClick={() => handleOpenModal(child)}
                      className="p-2.5 bg-slate-50 text-slate-400 rounded-xl hover:bg-blue-50 hover:text-blue-500 transition-all"
                    >
                      ✏️
                    </button>
                 </div>
              </div>
            </motion.div>
          ))}
        </div>

        {/* Modal Simplificado */}
        <AnimatePresence>
          {isModalOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
              <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                onClick={() => setIsModalOpen(false)}
                className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
              />
              <motion.form 
                onSubmit={handleSubmit}
                initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
                className="relative bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl"
              >
                <h3 className="text-2xl font-bold text-slate-800 mb-6 text-center">Perfil del Alumno</h3>
                <div className="space-y-4">
                  <div className="grid grid-cols-[2fr_1fr] gap-3">
                    <input 
                      required placeholder="Nombre completo" type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})}
                      className="bg-slate-50 border-2 border-slate-50 rounded-xl p-3 font-medium outline-none focus:border-blue-400 transition-all"
                    />
                    <input 
                      placeholder="Edad" type="number" value={formData.age} onChange={e => setFormData({...formData, age: parseInt(e.target.value)})}
                      className="bg-slate-50 border-2 border-slate-50 rounded-xl p-3 font-medium outline-none"
                    />
                  </div>
                  <select 
                    value={formData.level} onChange={e => setFormData({...formData, level: e.target.value as Level})}
                    className="w-full bg-slate-50 border-2 border-slate-50 rounded-xl p-3 font-medium outline-none"
                  >
                    {Object.values(Level).map(l => <option key={l} value={l}>{l}</option>)}
                  </select>
                  <textarea 
                    required value={formData.characteristics} onChange={e => setFormData({...formData, characteristics: e.target.value})}
                    className="w-full bg-slate-50 border-2 border-slate-50 rounded-xl p-3 font-medium h-24 resize-none outline-none focus:border-blue-400"
                    placeholder="Describe necesidades, estilo de aprendizaje y gustos..."
                  />
                  <div className="flex gap-3 pt-4">
                    <button type="submit" className="flex-1 bg-blue-600 text-white font-bold py-3.5 rounded-2xl shadow-lg shadow-blue-100">Guardar</button>
                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 bg-slate-50 text-slate-500 font-bold py-3.5 rounded-2xl">Cerrar</button>
                  </div>
                </div>
              </motion.form>
            </div>
          )}
        </AnimatePresence>
      </div>
    </Layout>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import Layout from '../components/Layout';
import { generateStreamingExercise, generateExerciseImage } from '../services/geminiService';
import { ExerciseType, Level, RewardTrigger, Child } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const AIGenerator: React.FC = () => {
  const [type, setType] = useState<ExerciseType>(ExerciseType.ARTICULATION);
  const [level, setLevel] = useState<Level>(Level.BASIC);
  const [topic, setTopic] = useState('');
  const [isLogOpen, setIsLogOpen] = useState(false);

  const [duration, setDuration] = useState(5);
  const [repetitions, setRepetitions] = useState(3);
  const [reward, setReward] = useState<RewardTrigger>(RewardTrigger.CONFETTI);

  const [isGenerating, setIsGenerating] = useState(false);
  const [isApproved, setIsApproved] = useState(false);
  const [streamedContent, setStreamedContent] = useState('');
  const [generatedExercise, setGeneratedExercise] = useState<any>(null);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setIsApproved(false);
    setStreamedContent('');
    setGeneratedExercise(null);

    const tempChild: Child = {
      id: 'preview',
      name: 'Explorador',
      age: 5,
      characteristics: topic,
      objectives: [],
      level: level,
      stars: 0,
      collection: []
    };

    try {
      const config = { duration, repetitions, reward };
      const result = await generateStreamingExercise(type, tempChild, config, (chunk) => {
        setStreamedContent(chunk);
      });

      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0].trim());
        const aiImageUrl = await generateExerciseImage(parsed.image_keyword || parsed.target, tempChild.age);
        parsed.imageUrl = aiImageUrl;
        parsed.config = config;
        setGeneratedExercise(parsed);
      }
    } catch (e) {
      console.error("Generación fallida:", e);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <Layout>
      <div className="max-w-6xl mx-auto px-4 pb-20">
        <header className="py-8 flex justify-between items-center mb-4">
          <div>
            <h2 className="text-3xl font-extrabold text-slate-800">Fábrica Mágica ✨</h2>
            <p className="text-slate-400 font-medium">Crea materiales educativos únicos con un solo click.</p>
          </div>
          <button 
            onClick={() => window.location.hash = '#/dashboard'} 
            className="text-slate-400 hover:text-slate-600 font-bold"
          >
            ← Volver
          </button>
        </header>

        <div className="grid lg:grid-cols-[1fr_1.5fr] gap-10 items-start">
          {/* Lado Configuración */}
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-50 space-y-8">
            <div className="space-y-4">
               <h4 className="text-xs font-black text-slate-300 uppercase tracking-[0.2em] mb-4">Ajustes del Reto</h4>

               <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 ml-1">Módulo</label>
                    <select className="w-full bg-slate-50 border-2 border-slate-50 rounded-xl p-3 font-bold text-sm" value={type} onChange={e => setType(e.target.value as ExerciseType)}>
                      {Object.values(ExerciseType).map(v => <option key={v} value={v}>{v}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 ml-1">Nivel</label>
                    <select className="w-full bg-slate-50 border-2 border-slate-50 rounded-xl p-3 font-bold text-sm" value={level} onChange={e => setLevel(e.target.value as Level)}>
                      {Object.values(Level).map(v => <option key={v} value={v}>{v}</option>)}
                    </select>
                  </div>
               </div>

               <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 ml-1">¿De qué trata el juego? (Topic)</label>
                  <input 
                    type="text" placeholder="Ej: Dinosaurios, Piratas, Frutas..." 
                    className="w-full bg-slate-50 border-2 border-slate-50 rounded-xl p-4 font-bold outline-none focus:border-blue-100 transition-all"
                    value={topic} onChange={e => setTopic(e.target.value)} 
                  />
               </div>

               <div className="grid grid-cols-2 gap-4 pt-4">
                  <div>
                    <label className="text-xs font-bold text-slate-500 block mb-2">Duración: {duration} min</label>
                    <input type="range" min="1" max="15" className="w-full accent-blue-600" value={duration} onChange={e => setDuration(parseInt(e.target.value))} />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 block mb-2">Premios: {reward === RewardTrigger.CONFETTI ? '🎉' : '⭐'}</label>
                    <div className="flex gap-2">
                       <button onClick={() => setReward(RewardTrigger.CONFETTI)} className={`flex-1 p-2 rounded-lg text-sm font-bold border-2 ${reward === RewardTrigger.CONFETTI ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-50 text-slate-300'}`}>Confeti</button>
                       <button onClick={() => setReward(RewardTrigger.STARS)} className={`flex-1 p-2 rounded-lg text-sm font-bold border-2 ${reward === RewardTrigger.STARS ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-50 text-slate-300'}`}>Estrellas</button>
                    </div>
                  </div>
               </div>
            </div>

            <button 
              onClick={handleGenerate} 
              disabled={isGenerating || !topic} 
              className="w-full bg-blue-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all disabled:opacity-30 flex items-center justify-center gap-3"
            >
              {isGenerating ? (
                <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin" />
              ) : "✨ GENERAR JUEGO"}
            </button>
          </div>

          {/* Lado Preview */}
          <div className="space-y-6">
            <div className="bg-slate-50 p-6 rounded-[2.5rem] min-h-[500px] flex flex-col border border-slate-100">
               <div className="flex justify-between items-center mb-4">
                  <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest">Resultado del Diseño</h4>
                  <button onClick={() => setIsLogOpen(!isLogOpen)} className="text-[10px] font-black text-slate-300 hover:text-slate-500 uppercase">
                    {isLogOpen ? 'Cerrar Log' : 'Ver Log IA'}
                  </button>
               </div>

               <AnimatePresence>
                 {isLogOpen && (
                   <motion.div initial={{ height: 0 }} animate={{ height: 'auto' }} exit={{ height: 0 }} className="overflow-hidden mb-6">
                      <div className="bg-slate-900 text-green-400 p-4 rounded-xl text-[10px] font-mono whitespace-pre-wrap h-24 overflow-y-auto">
                        {streamedContent || "Esperando..."}
                      </div>
                   </motion.div>
                 )}
               </AnimatePresence>

               <div className="flex-grow flex flex-col items-center justify-center">
                  <AnimatePresence mode="wait">
                    {isGenerating ? (
                      <motion.div key="loader" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="flex flex-col items-center gap-4">
                         <div className="w-20 h-20 bg-white rounded-3xl shadow-lg flex items-center justify-center animate-bounce">
                           <span className="text-4xl">🎨</span>
                         </div>
