                <div className="flex flex-col items-center gap-6">
                   {feedbackMsg && <motion.div initial={{ y: 10, opacity: 0 }} animate={{ y: 0, opacity: 1 }} className="bg-yellow-400 px-8 py-3 rounded-full font-black text-blue-900 text-xl border-4 border-white shadow-lg">{feedbackMsg}</motion.div>}
