import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Layout from '../components/Layout';
import { motion, AnimatePresence, Variants } from 'framer-motion';
import LottiePlayer from '../components/LottiePlayer';
import { LOTTIE_URLS } from '../constants';
import { speak, startRecognition, compareText } from '../services/speechService';
import { generateStreamingExercise, generateExerciseImage } from '../services/geminiService';
import { ExerciseType, Level, RewardTrigger, Child } from '../types';

type PlayStep = 'welcome' | 'selection' | 'generating' | 'playing' | 'feedback';

// Variantes para el efecto "Slide" solicitado - Agregado tipo Variants y as const para evitar errores de tipado de Framer Motion
const slideVariants: Variants = {
  enter: (direction: number) => ({
    x: direction > 0 ? '100%' : '-100%',
    opacity: 0,
    scale: 0.98
  }),
  center: {
    zIndex: 1,
    x: 0,
    opacity: 1,
    scale: 1,
    transition: {
      x: { type: "tween" as const, ease: "easeInOut" as const, duration: 0.4 },
      opacity: { duration: 0.4 },
      scale: { duration: 0.4 }
    }
  },
  exit: (direction: number) => ({
    zIndex: 0,
    x: direction < 0 ? '100%' : '-100%',
    opacity: 0,
    scale: 1.02,
    transition: {
      x: { type: "tween" as const, ease: "easeInOut" as const, duration: 0.4 },
      opacity: { duration: 0.4 }
    }
  })
};

const ChildPlay: React.FC = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const [currentChild, setCurrentChild] = useState<Child | null>(null);
  const [currentStep, setCurrentStep] = useState<PlayStep>('welcome');
  const [direction, setDirection] = useState(1); // 1 para adelante, -1 para atrás
  const [mascotState, setMascotState] = useState(LOTTIE_URLS.mascot_happy);
  const [isListening, setIsListening] = useState(false);
  const [feedbackMsg, setFeedbackMsg] = useState('');
  const [showStars, setShowStars] = useState(false);
  const [generatedExercise, setGeneratedExercise] = useState<any>(null);

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem('hja_children') || '[]');
    const child = saved.find((c: any) => c.id === id);
    if (child) setCurrentChild(child);
    else navigate('/dashboard');
  }, [id, navigate]);

  const changeStep = (newStep: PlayStep, newDirection: number = 1) => {
    setDirection(newDirection);
    setCurrentStep(newStep);
  };

  const fetchNewExercise = async (type: ExerciseType) => {
    if (!currentChild) return;
    changeStep('generating', 1);
    setMascotState(LOTTIE_URLS.mascot_encourage);

    try {
      const result = await generateStreamingExercise(
        type, 
        currentChild, 
        { duration: 5, repetitions: 3, reward: RewardTrigger.STARS }, 
        () => {}
      );
      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0].trim());
        const aiImageUrl = await generateExerciseImage(parsed.image_keyword || parsed.target, currentChild.age);
        parsed.imageUrl = aiImageUrl;
        setGeneratedExercise(parsed);
        changeStep('playing', 1);
        setMascotState(LOTTIE_URLS.mascot_happy);
        speak(parsed.content);
      }
    } catch (e) {
      changeStep('selection', -1);
    }
  };

  const handleListen = useCallback(() => {
    if (isListening || !generatedExercise) return;
    setIsListening(true);
    setMascotState(LOTTIE_URLS.mascot_encourage);
    setFeedbackMsg('👂 ¡Te escucho!');

    startRecognition(
      (result) => {
        setIsListening(false);
        if (compareText(result, generatedExercise.target || '') > 0.6) {
          setMascotState(LOTTIE_URLS.mascot_celebrate);
          setFeedbackMsg('🌟 ¡EXCELENTE!');
          setShowStars(true);
          speak("¡Muy bien!");
          setTimeout(() => { 
            setShowStars(false); 
            changeStep('feedback', 1); 
          }, 2000);
        } else {
          setMascotState(LOTTIE_URLS.mascot_happy);
          setFeedbackMsg('💪 ¡Casi! Intenta de nuevo');
          speak("¿Otra vez?");
        }
      },
      () => setIsListening(false)
    );
  }, [generatedExercise, isListening]);

  return (
    <Layout role="child">
      <div className="h-full w-full max-w-6xl mx-auto flex flex-col items-center justify-center p-4 relative overflow-hidden">
        <AnimatePresence mode="wait" custom={direction}>
          {currentStep === 'welcome' && (
            <motion.div 
              key="welcome" 
              custom={direction}
              variants={slideVariants}
              initial="enter"
              animate="center"
              exit="exit"
              className="text-center bg-white/95 p-12 rounded-[4rem] shadow-2xl border-[15px] border-white max-w-md w-full"
            >
              <div className="w-56 h-56 mx-auto mb-6"><LottiePlayer url={LOTTIE_URLS.mascot_happy} /></div>
              <h2 className="text-4xl font-black text-blue-900 mb-8 uppercase tracking-tighter">¡Hola {currentChild?.name.split(' ')[0]}!</h2>
              <button 
                onClick={() => changeStep('selection', 1)}
                className="w-full bg-yellow-400 text-blue-900 text-3xl font-black py-6 rounded-[2.5rem] shadow-[0_12px_0_#ca8a04] border-4 border-white active:translate-y-2 transition-all"
              >
                ¡JUGAR! 🚀
              </button>
            </motion.div>
          )}

          {currentStep === 'selection' && (
            <motion.div 
              key="selection" 
              custom={direction}
              variants={slideVariants}
              initial="enter"
              animate="center"
              exit="exit"
              className="w-full flex flex-col items-center"
            >
              <h2 className="text-4xl font-black text-blue-900 text-center mb-12 drop-shadow-sm uppercase">¿Qué quieres practicar hoy?</h2>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-8 w-full max-w-5xl">
                {[
                  { type: ExerciseType.ARTICULATION, icon: '👄', color: 'bg-orange-400' },
                  { type: ExerciseType.VOCABULARY, icon: '🍎', color: 'bg-green-500' },
                  { type: ExerciseType.COMPREHENSION, icon: '🧠', color: 'bg-purple-500' },
                  { type: ExerciseType.SENTENCES, icon: '📝', color: 'bg-blue-500' }
                ].map((mod) => (
                  <motion.button
                    key={mod.type} 
                    whileHover={{ scale: 1.05, y: -5 }} 
                    whileTap={{ scale: 0.95 }}
                    onClick={() => fetchNewExercise(mod.type)}
                    className={`${mod.color} aspect-square rounded-[3rem] border-[10px] border-white shadow-2xl flex flex-col items-center justify-center text-white`}
                  >
                    <span className="text-6xl md:text-7xl mb-4">{mod.icon}</span>
                    <span className="font-black text-lg md:text-xl uppercase tracking-tighter">{mod.type}</span>
                  </motion.button>
                ))}
              </div>
              <button 
                onClick={() => changeStep('welcome', -1)}
                className="mt-12 text-blue-500 font-black uppercase text-sm hover:underline"
              >
                ← Volver al inicio
              </button>
            </motion.div>
          )}

          {currentStep === 'generating' && (
             <motion.div 
               key="gen" 
               custom={direction}
               variants={slideVariants}
               initial="enter"
               animate="center"
               exit="exit"
               className="text-center"
             >
               <div className="w-72 h-72 mx-auto"><LottiePlayer url={LOTTIE_URLS.clouds} /></div>
               <h3 className="text-4xl font-black text-blue-900 animate-pulse mt-4 uppercase tracking-widest">Creando magia... ✨</h3>
             </motion.div>
          )}

          {currentStep === 'playing' && generatedExercise && (
            <motion.div 
              key="play" 
              custom={direction}
              variants={slideVariants}
              initial="enter"
              animate="center"
              exit="exit"
              className="w-full h-full flex flex-col lg:flex-row items-center justify-between gap-10"
            >
              {/* Imagen Grande y Central */}
              <div className="flex-1 w-full max-w-xl bg-white p-8 rounded-[4rem] border-[15px] border-blue-50 shadow-2xl flex flex-col text-center">
                 <div className="aspect-square rounded-[3rem] overflow-hidden border-4 border-slate-50 mb-8 bg-blue-50 flex items-center justify-center">
                    <img src={generatedExercise.imageUrl} className="w-full h-full object-contain p-8 animate-float" alt="Juego" />
                 </div>
                 <h3 className="text-3xl md:text-4xl font-black text-blue-950 leading-tight mb-2 uppercase">{generatedExercise.content}</h3>
                 <p className="text-blue-400 font-bold uppercase tracking-widest text-sm">Di la palabra mágica: <span className="text-blue-600 underline">{generatedExercise.target}</span></p>
              </div>

              {/* Controles Minimalistas */}
              <div className="flex flex-col items-center gap-12 lg:w-80">
                <div className="w-64 h-64 relative">
                   <LottiePlayer url={mascotState} />
                   {showStars && <div className="absolute inset-0 scale-150 pointer-events-none"><LottiePlayer url={LOTTIE_URLS.stars} /></div>}
                </div>

                <div className="flex flex-col items-center gap-6">
                   {feedbackMsg && (
                     <motion.div 
                       initial={{ y: 10, opacity: 0 }} 
                       animate={{ y: 0, opacity: 1 }} 
                       className="bg-yellow-400 px-8 py-3 rounded-full font-black text-blue-900 text-xl border-4 border-white shadow-lg"
                     >
                       {feedbackMsg}
                     </motion.div>
                   )}
                   <div className="flex gap-4">
                      <button onClick={() => speak(generatedExercise.content)} className="bg-blue-500 w-20 h-20 rounded-3xl text-3xl text-white shadow-xl hover:scale-110 active:scale-95 transition-all flex items-center justify-center">🔊</button>
                      <button 
                        onClick={handleListen}
                        className={`w-32 h-32 rounded-full text-6xl flex items-center justify-center text-white border-[10px] shadow-2xl transition-all ${isListening ? 'bg-red-500 border-red-200 scale-110 animate-pulse' : 'bg-green-500 border-green-200'}`}
                      >
                        {isListening ? '🛑' : '🎤'}
                      </button>
                   </div>
                </div>
              </div>
            </motion.div>
          )}

          {currentStep === 'feedback' && (
             <motion.div 
               key="feed" 
               custom={direction}
               variants={slideVariants}
               initial="enter"
               animate="center"
               exit="exit"
               className="bg-white p-12 rounded-[5rem] border-[15px] border-yellow-200 text-center max-w-lg w-full shadow-2xl"
             >
               <div className="text-9xl mb-6">🌈</div>
               <h2 className="text-5xl font-black text-blue-900 mb-10 leading-none">¡GENIAL, LO HICIMOS!</h2>
               <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => changeStep('selection', -1)} className="bg-blue-500 text-white font-black py-6 rounded-3xl text-2xl shadow-lg active:translate-y-1">Otro juego 🍎</button>
                  <button onClick={() => navigate('/dashboard')} className="bg-slate-100 text-slate-500 font-black py-6 rounded-3xl text-2xl active:translate-y-1">Terminar 🏠</button>
               </div>
             </motion.div>
          )}
        </AnimatePresence>
      </div>

      <style>{`
        @keyframes float {
          0% { transform: translateY(0px); }
          50% { transform: translateY(-15px); }
          100% { transform: translateY(0px); }
        }
        .animate-float {
          animation: float 4s ease-in-out infinite;
        }
      `}</style>
    </Layout>
  );
};

export default ChildPlay;
